@app.get("/api/health")
async def health_check():
    """Endpoint de sante pour Docker HEALTHCHECK et monitoring OVH."""
    checks = {"status": "ok", "version": "3.9.0", "env": "ovhcloud" if _IS_OVH else "vercel"}
    try:
        db = get_db()
        checks["database"] = "ok"
    except Exception as e:
        checks["database"] = f"error: {str(e)}"
        checks["status"] = "degraded"
    if _IS_OVH:
        checks["persistence"] = "active" if _persist else "fallback_memory"
        checks["data_dir"] = str(_DATA_DIR)
        checks["data_writable"] = os.access(str(_DATA_DIR), os.W_OK)
        try:
            stats = get_data_stats()
            checks["data_stats"] = stats
        except Exception:
            pass
    checks["max_files"] = _MAX_FILES
    checks["max_upload_mb"] = _MAX_UPLOAD_MB
    return checks


@app.get("/api/pricing")
async def get_pricing():
    """Retourne la grille tarifaire officielle (source unique de verite).

    Tous les prix sont mensuels HT. L'equivalent annuel est calcule automatiquement.
    """
    plans = []
    for key, plan in _PRICING.items():
        plans.append({
            "id": key,
            "label": plan["label"],
            "prix_mensuel_ht": plan["prix_mensuel"],
            "prix_annuel_ht": round(plan["prix_mensuel"] * 12, 2),
            "profils_max": plan["profils"],
            "periodicite": "mensuel",
        })
    return {"plans": plans, "devise": "EUR", "tva": "applicable en sus"}


