# ==============================
# BIBLIOTHEQUE DE CONNAISSANCES
# ==============================

def _alimenter_knowledge(result):
    """Alimente la base de connaissances a partir d'un resultat d'analyse."""
    kb = _biblio_knowledge
    kb["derniere_maj"] = datetime.now().isoformat()

    for decl in result.declarations:
        # --- Employeur ---
        if decl.employeur:
            siret = decl.employeur.siret or ""
            if siret:
                kb["employeurs"][siret] = {
                    "siren": decl.employeur.siren,
                    "siret": siret,
                    "raison_sociale": decl.employeur.raison_sociale,
                    "effectif": decl.employeur.effectif,
                    "code_naf": decl.employeur.code_naf,
                    "derniere_maj": datetime.now().isoformat(),
                }
                # Effectif par periode
                periode = ""
                if decl.periode and decl.periode.debut:
                    periode = decl.periode.debut.strftime("%Y-%m")
                if periode and decl.employeur.effectif:
                    kb["effectifs"][periode] = decl.employeur.effectif

        # --- Periode ---
        if decl.periode and decl.periode.debut:
            per = decl.periode.debut.strftime("%Y-%m")
            if per not in kb["periodes_couvertes"]:
                kb["periodes_couvertes"].append(per)
                kb["periodes_couvertes"].sort()

        # --- Type de document ---
        fmt = (decl.type_declaration or "").lower()
        meta = getattr(decl, "metadata", {}) or {}
        doc_type = meta.get("type_document", "")
        per_kb = decl.periode.debut.strftime("%Y-%m") if decl.periode and decl.periode.debut else ""
        if fmt in ("dsn", "dsn/xml"):
            kb["declarations_dsn"].append({
                "reference": decl.reference,
                "periode": per_kb,
                "nb_salaries": len(decl.employes),
                "nb_cotisations": len(decl.cotisations),
                "masse_salariale": float(decl.masse_salariale_brute),
                "s89_total_cotisations": meta.get("s89_total_cotisations", 0),
                "s89_total_brut": meta.get("s89_total_brut", 0),
                "date_import": datetime.now().isoformat(),
            })
            if "dsn" not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"]["dsn"] = []
            kb["pieces_justificatives"]["dsn"].append(decl.reference)
        elif fmt == "bulletin" or doc_type == "bulletin_de_paie" or (len(decl.cotisations) > 0 and len(decl.employes) <= 1):
            kb["bulletins_paie"].append({
                "reference": decl.reference,
                "nb_salaries": len(decl.employes),
                "nb_cotisations": len(decl.cotisations),
                "masse_salariale": float(decl.masse_salariale_brute),
                "net_a_payer": meta.get("net_a_payer", 0),
                "total_patronal": meta.get("total_patronal", 0),
                "total_salarial": meta.get("total_salarial", 0),
                "periode": per_kb,
                "date_import": datetime.now().isoformat(),
            })
            if "bulletins" not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"]["bulletins"] = []
            kb["pieces_justificatives"]["bulletins"].append(decl.reference)
        elif fmt == "livre_de_paie" or doc_type == "livre_de_paie":
            kb["bulletins_paie"].append({
                "reference": decl.reference,
                "nb_salaries": len(decl.employes),
                "nb_cotisations": len(decl.cotisations),
                "masse_salariale": float(decl.masse_salariale_brute),
                "periode": per_kb,
                "date_import": datetime.now().isoformat(),
            })
            if "livre_de_paie" not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"]["livre_de_paie"] = []
            kb["pieces_justificatives"]["livre_de_paie"].append(decl.reference)
        elif fmt == "facture" or doc_type in ("facture_achat", "facture_vente"):
            if "factures" not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"]["factures"] = []
            kb["pieces_justificatives"]["factures"].append(decl.reference)
        elif fmt == "contrat" or doc_type == "contrat_de_travail":
            if "contrats" not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"]["contrats"] = []
            kb["pieces_justificatives"]["contrats"].append(decl.reference)
        elif fmt == "accord" or doc_type.startswith("accord_"):
            if "accords" not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"]["accords"] = []
            kb["pieces_justificatives"]["accords"].append(decl.reference)
            # Store accord details in enterprise context
            ctx = kb.get("contexte_entreprise", {})
            accords = ctx.get("accords_entreprise", [])
            accords.append({
                "reference": decl.reference,
                "type": doc_type,
                "date": meta.get("date_accord", ""),
                "signataires": meta.get("signataires", []),
            })
            ctx["accords_entreprise"] = accords
            # CCN from accord
            ccn_accord = meta.get("convention_collective", "")
            if ccn_accord and not ctx.get("convention_collective"):
                ctx["convention_collective"] = ccn_accord
                # Try to identify CCN code for prevoyance rules
                try:
                    from urssaf_analyzer.rules.contribution_rules import ContributionRules as _CRccn
                    ccn_code = _CRccn().identifier_ccn(ccn_accord)
                    if ccn_code:
                        ctx["ccn_code"] = ccn_code
                except Exception:
                    pass
            kb["contexte_entreprise"] = ctx
        elif fmt == "pv_ag" or doc_type.startswith("pv_ag"):
            if "pv_ag" not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"]["pv_ag"] = []
            kb["pieces_justificatives"]["pv_ag"].append(decl.reference)
        elif fmt == "contrat_service" or doc_type == "contrat_service":
            if "contrats_service" not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"]["contrats_service"] = []
            kb["pieces_justificatives"]["contrats_service"].append(decl.reference)
        # --- Fiscal documents ---
        elif fmt in ("liasse_fiscale", "declaration_tva", "declaration_is", "das2",
                      "taxe_salaires", "cfe_cvae", "fec", "releve_frais_generaux",
                      "avis_imposition", "bordereau_urssaf") or \
             doc_type in ("liasse_fiscale", "declaration_tva", "declaration_is", "das2",
                          "taxe_salaires", "cfe_cvae", "fec", "releve_frais_generaux",
                          "avis_imposition", "bordereau_urssaf"):
            cat = "fiscal"
            if cat not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"][cat] = []
            kb["pieces_justificatives"][cat].append(decl.reference)
            # Extract fiscal data to enterprise context
            ctx = kb.get("contexte_entreprise", {})
            if meta.get("resultat"):
                ctx["resultat_fiscal"] = meta["resultat"]
            if meta.get("chiffre_affaires"):
                ctx["chiffre_affaires"] = meta["chiffre_affaires"]
            if meta.get("regime_fiscal") or doc_type == "declaration_is":
                ctx["regime_fiscal"] = "IS"
            kb["contexte_entreprise"] = ctx
        # --- Comptable documents ---
        elif fmt in ("bilan", "compte_resultat", "rapport_cac", "rapport_gestion", "budget") or \
             doc_type in ("bilan", "compte_resultat", "rapport_cac", "rapport_gestion", "budget"):
            cat = "comptable"
            if cat not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"][cat] = []
            kb["pieces_justificatives"][cat].append(decl.reference)
            ctx = kb.get("contexte_entreprise", {})
            if meta.get("resultat_net"):
                ctx["resultat_net"] = meta["resultat_net"]
            if meta.get("chiffre_affaires"):
                ctx["chiffre_affaires"] = meta["chiffre_affaires"]
            if meta.get("capitaux_propres"):
                ctx["capitaux_propres"] = meta["capitaux_propres"]
            kb["contexte_entreprise"] = ctx
        # --- Social/RH documents ---
        elif fmt in ("dpae", "registre_personnel", "duerp", "reglement_interieur",
                      "avenant", "bilan_social", "note_frais",
                      "rupture_conventionnelle", "cse", "france_travail",
                      "medecine_travail", "epargne_salariale", "licenciement",
                      "formation", "mutuelle_prevoyance", "dsn") or \
             doc_type in ("dpae", "registre_personnel", "duerp", "reglement_interieur",
                          "avenant", "bilan_social", "note_frais",
                          "rupture_conventionnelle", "cse", "france_travail",
                          "medecine_travail", "epargne_salariale", "licenciement",
                          "formation", "mutuelle_prevoyance",
                          "pv_cse", "budget_cse", "rapport_cse", "elections_cse",
                          "attestation_are", "radiation", "autorisation_licenciement",
                          "visite_embauche", "visite_reprise", "vip",
                          "pee", "perco", "per", "due_mutuelle",
                          "attestation_formation", "plan_formation",
                          "bilan_competences", "vae",
                          "dsn", "dsn_mensuelle", "dsn_evenementielle",
                          "dsn_fin_contrat", "dsn_arret_travail"):
            cat = "social_rh"
            if cat not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"][cat] = []
            kb["pieces_justificatives"][cat].append(decl.reference)
        # --- Juridique documents ---
        elif fmt in ("statuts", "kbis", "bail", "assurance", "lettre_mission") or \
             doc_type in ("statuts", "kbis", "bail", "assurance", "lettre_mission"):
            cat = "juridique"
            if cat not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"][cat] = []
            kb["pieces_justificatives"][cat].append(decl.reference)
            ctx = kb.get("contexte_entreprise", {})
            if meta.get("forme_juridique") and not ctx.get("forme_juridique"):
                ctx["forme_juridique"] = meta["forme_juridique"]
            if meta.get("capital_social"):
                ctx["capital_social"] = meta["capital_social"]
            if meta.get("siege_social") and not ctx.get("lieu_implantation"):
                ctx["lieu_implantation"] = meta["siege_social"]
            if meta.get("denomination") and not ctx.get("raison_sociale"):
                ctx["raison_sociale"] = meta["denomination"]
            kb["contexte_entreprise"] = ctx
        # --- Commercial documents ---
        elif fmt in ("devis", "avoir", "bon_commande", "releve_bancaire", "cerfa") or \
             doc_type in ("devis", "avoir", "bon_commande", "releve_bancaire", "cerfa"):
            cat = "commercial"
            if cat not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"][cat] = []
            kb["pieces_justificatives"][cat].append(decl.reference)
        elif len(decl.cotisations) > 0 or float(decl.masse_salariale_brute) > 0:
            kb["bulletins_paie"].append({
                "reference": decl.reference,
                "nb_salaries": len(decl.employes),
                "nb_cotisations": len(decl.cotisations),
                "masse_salariale": float(decl.masse_salariale_brute),
                "periode": per_kb,
                "date_import": datetime.now().isoformat(),
            })
            if "autres" not in kb["pieces_justificatives"]:
                kb["pieces_justificatives"]["autres"] = []
            kb["pieces_justificatives"]["autres"].append(decl.reference)

        # --- Salaries ---
        for emp in decl.employes:
            nir = emp.nir or f"unknown_{emp.id}"
            existing = kb["salaries"].get(nir, {})
            cots = [c for c in decl.cotisations if c.employe_id == emp.id]
            brut = float(sum(c.base_brute for c in cots)) if cots else 0
            if brut <= 0 and float(decl.masse_salariale_brute) > 0:
                brut = float(decl.masse_salariale_brute) / max(len(decl.employes), 1)
            statut = "cadre" if emp.statut and "cadre" in emp.statut.lower() else "non-cadre"
            kb["salaries"][nir] = {
                "nir": nir,
                "nom": emp.nom or existing.get("nom", ""),
                "prenom": emp.prenom or existing.get("prenom", ""),
                "date_naissance": emp.date_naissance.isoformat() if emp.date_naissance else existing.get("date_naissance", ""),
                "statut": statut,
                "dernier_brut": brut if brut > 0 else existing.get("dernier_brut", 0),
                "periodes_presentes": list(set(existing.get("periodes_presentes", []) + ([decl.periode.debut.strftime("%Y-%m")] if decl.periode and decl.periode.debut else []))),
                "derniere_maj": datetime.now().isoformat(),
            }

        # --- Cotisations et taux ---
        per_str = decl.periode.debut.strftime("%Y-%m") if decl.periode and decl.periode.debut else ""
        for cot in decl.cotisations:
            code = cot.type_cotisation.value if cot.type_cotisation else ""
            libelle = code.replace("_", " ").title()
            kb["cotisations"].append({
                "code": code,
                "libelle": libelle,
                "base": float(cot.base_brute),
                "taux_salarial": float(cot.taux_salarial) if cot.taux_salarial else 0,
                "taux_patronal": float(cot.taux_patronal) if cot.taux_patronal else 0,
                "montant_salarial": float(cot.montant_salarial) if cot.montant_salarial else 0,
                "montant_patronal": float(cot.montant_patronal) if cot.montant_patronal else 0,
                "employe_nir": cot.employe_id,
                "periode": per_str,
            })
            # Verification des taux
            if code and cot.taux_salarial:
                kb["taux_verifies"][code] = {
                    "taux_constate": float(cot.taux_salarial),
                    "base": float(cot.base_brute),
                    "conforme": None,  # sera evalue par l'audit
                }

        # --- Masse salariale ---
        if float(decl.masse_salariale_brute) > 0:
            per = decl.periode.debut.strftime("%Y-%m") if decl.periode and decl.periode.debut else "sans_periode"
            kb["masse_salariale"][per] = kb["masse_salariale"].get(per, 0) + float(decl.masse_salariale_brute)
            kb["masse_salariale_totale"] = kb.get("masse_salariale_totale", 0) + float(decl.masse_salariale_brute)

        # --- Contexte entreprise ---
        meta = getattr(decl, "metadata", {}) or {}
        if decl.employeur:
            ctx = kb.get("contexte_entreprise", {})
            if decl.employeur.code_naf and not ctx.get("code_naf"):
                ctx["code_naf"] = decl.employeur.code_naf
            if decl.employeur.raison_sociale and not ctx.get("raison_sociale"):
                ctx["raison_sociale"] = decl.employeur.raison_sociale
            if decl.employeur.effectif and decl.employeur.effectif > ctx.get("effectif_moyen", 0):
                ctx["effectif_moyen"] = decl.employeur.effectif
            kb["contexte_entreprise"] = ctx

        # Convention collective detection from employee data
        for emp in decl.employes:
            if emp.convention_collective and emp.convention_collective not in ("Employe", "Cadre", "non-cadre"):
                ctx = kb.get("contexte_entreprise", {})
                if emp.convention_collective not in (ctx.get("convention_collective", ""), ""):
                    if not ctx.get("convention_collective"):
                        ctx["convention_collective"] = emp.convention_collective
                kb["contexte_entreprise"] = ctx

        # CCN from metadata
        ccn_from_meta = meta.get("convention_collective", "")
        if ccn_from_meta and ccn_from_meta not in kb.get("conventions_collectives", []):
            kb["conventions_collectives"].append(ccn_from_meta)

        # Document type tracking
        doc_type_key = meta.get("type_document", "") or fmt or "inconnu"
        if doc_type_key not in kb.get("documents_par_type", {}):
            kb["documents_par_type"][doc_type_key] = []
        kb["documents_par_type"][doc_type_key].append(decl.reference)

    # --- Anomalies ---
    for f in result.findings:
        kb["anomalies_detectees"].append({
            "id": f.id,
            "categorie": f.categorie.value,
            "severite": f.severite.value,
            "titre": f.titre,
            "reference_legale": f.reference_legale,
        })


def _get_knowledge_summary() -> dict:
    """Resume l'etat de la base de connaissances pour l'audit."""
    kb = _biblio_knowledge
    nb_sal = len(kb["salaries"])
    nb_cadres = sum(1 for s in kb["salaries"].values() if s.get("statut") == "cadre")
    has_dsn = len(kb["declarations_dsn"]) > 0
    has_bulletins = len(kb["bulletins_paie"]) > 0
    has_multi_docs = len(kb["pieces_justificatives"]) > 1
    nb_periodes = len(kb["periodes_couvertes"])
    nb_cotisations = len(kb["cotisations"])
    total_masse = kb.get("masse_salariale_totale", 0) or sum(kb["masse_salariale"].values())
    nb_anomalies = len(kb["anomalies_detectees"])
    nb_employeurs = len(kb["employeurs"])
    # Pieces disponibles
    pieces = list(kb["pieces_justificatives"].keys())
    # Contrats RH enregistres
    nb_contrats = len(_rh_contrats)
    nb_contrats_actifs = sum(1 for c in _rh_contrats if c.get("statut") == "actif")
    # Visites medicales
    nb_visites = len(_rh_visites_med)
    # Entretiens
    nb_entretiens = len(_rh_entretiens)

    # Types de cotisations presentes
    types_cot = {}
    for cot in kb["cotisations"]:
        code = cot.get("code", "")
        if code:
            if code not in types_cot:
                types_cot[code] = {"count": 0, "total_patronal": 0, "total_salarial": 0}
            types_cot[code]["count"] += 1
            types_cot[code]["total_patronal"] += cot.get("montant_patronal", 0)
            types_cot[code]["total_salarial"] += cot.get("montant_salarial", 0)

    ctx = kb.get("contexte_entreprise", {})
    docs_par_type = kb.get("documents_par_type", {})

    return {
        "nb_salaries_connus": nb_sal,
        "nb_cadres": nb_cadres,
        "nb_employeurs": nb_employeurs,
        "has_dsn": has_dsn,
        "has_bulletins": has_bulletins,
        "has_multi_docs": has_multi_docs,
        "nb_periodes": nb_periodes,
        "periodes": kb["periodes_couvertes"],
        "nb_cotisations_analysees": nb_cotisations,
        "total_masse_salariale": total_masse,
        "nb_anomalies": nb_anomalies,
        "pieces_disponibles": pieces,
        "nb_contrats_rh": nb_contrats,
        "nb_contrats_actifs": nb_contrats_actifs,
        "nb_visites_medicales": nb_visites,
        "nb_entretiens": nb_entretiens,
        "taux_verifies": kb["taux_verifies"],
        "exonerations": kb["exonerations_detectees"],
        "conventions": kb["conventions_collectives"],
        "derniere_maj": kb["derniere_maj"],
        "types_cotisations": types_cot,
        "contexte_entreprise": ctx,
        "documents_par_type": docs_par_type,
    }


# ==============================
# ANALYSE
# ==============================

@app.post("/api/analyze")
async def analyser_documents(
    request: Request,
    fichiers: list[UploadFile] = File(...),
    format_rapport: str = Query("json"),
    integrer: bool = Query(True),
    mode_analyse: str = Query("complet"),
):
    user = get_optional_user(request)
    user_email = user["email"] if user else "utilisateur"
    if len(fichiers) > _MAX_FILES:
        raise HTTPException(400, f"Maximum {_MAX_FILES} fichiers par analyse.")

    config = AppConfig(base_dir=_DATA_DIR)
    orchestrator = Orchestrator(config)

    with tempfile.TemporaryDirectory() as td:
        chemins = []
        total_size = 0
        for f in fichiers:
            data = await f.read()
            if len(data) > _MAX_FILE_MB * 1024 * 1024:
                raise HTTPException(400, f"Fichier '{f.filename}' depasse la limite de {_MAX_FILE_MB} Mo.")
            total_size += len(data)
            if total_size > _MAX_UPLOAD_MB * 1024 * 1024:
                raise HTTPException(400, f"Taille totale depasse {_MAX_UPLOAD_MB} Mo.")
            # Securite : empecher le path traversal via filename
            raw_name = (f.filename or "").replace("\\", "/")
            safe_name = Path(raw_name).name if raw_name else ""
            if not safe_name or safe_name.startswith("."):
                safe_name = f"upload_{len(chemins)}"
            # Eviter les collisions si deux fichiers ont le meme nom
            chemin = Path(td) / safe_name
            if chemin.exists():
                stem = Path(safe_name).stem
                suffix = Path(safe_name).suffix
                safe_name = f"{stem}_{len(chemins)}{suffix}"
                chemin = Path(td) / safe_name
            chemin.write_bytes(data)
            chemins.append(chemin)

        try:
            orchestrator.analyser_documents(chemins, format_rapport)
        except URSSAFAnalyzerError as e:
            raise HTTPException(422, str(e))
        except Exception:
            raise HTTPException(500, "Erreur interne lors de l'analyse")

        result = orchestrator.result

        # --- Build document-to-declaration mapping by source_document_id ---
        # Each document has a unique id; declarations reference it via source_document_id
        _doc_to_decls = {}
        for decl in result.declarations:
            did = decl.source_document_id
            if did:
                _doc_to_decls.setdefault(did, []).append(decl)
        # Also build ordered list of documents (same order as chemins/fichiers)
        _docs_ordered = result.documents_analyses

        # --- Alimenter la bibliotheque de connaissances ---
        _alimenter_knowledge(result)

        if integrer:
            for idx_f, f in enumerate(fichiers):
                await f.seek(0)
                raw = await f.read()
                sha = hashlib.sha256(raw).hexdigest()[:16]
                # Find declarations for this file using source_document_id
                doc_data = {}
                doc_statut = "analyse"
                matched_decl = None
                if idx_f < len(_docs_ordered):
                    doc_obj = _docs_ordered[idx_f]
                    matching = _doc_to_decls.get(doc_obj.id, [])
                    if matching:
                        matched_decl = matching[0]  # primary declaration
                        d_meta_lib = getattr(matched_decl, "metadata", {}) or {}
                        doc_type_lib = d_meta_lib.get("type_document", "")
                        if doc_type_lib == "inconnu" or not doc_type_lib:
                            doc_statut = "non_reconnu"
                        doc_data = {
                            "nb_salaries": len(matched_decl.employes),
                            "nb_cotisations": len(matched_decl.cotisations),
                            "masse_salariale": float(matched_decl.masse_salariale_brute),
                            "type_declaration": matched_decl.type_declaration,
                            "type_document": doc_type_lib or "inconnu",
                            "employeur_siret": matched_decl.employeur.siret if matched_decl.employeur else "",
                            "employeur_nom": matched_decl.employeur.raison_sociale if matched_decl.employeur else "",
                            "periode": matched_decl.periode.debut.strftime("%Y-%m") if matched_decl.periode and matched_decl.periode.debut else "",
                            "salaries_noms": [f"{e.prenom} {e.nom}" for e in matched_decl.employes],
                        }
                    else:
                        doc_statut = "erreur"
                else:
                    doc_statut = "erreur"
                _doc_library.append({
                    "id": str(uuid.uuid4())[:8],
                    "nom": f.filename,
                    "taille": len(raw),
                    "sha256": sha,
                    "date_import": datetime.now().isoformat(),
                    "statut": doc_statut,
                    "nature": doc_data.get("type_document", "inconnu"),
                    "donnees_extraites": doc_data,
                    "actions": [{"action": "import+analyse", "par": "utilisateur", "date": datetime.now().isoformat()}],
                    "erreurs_corrigees": [],
                })
            log_action(user_email, "analyse", f"{len(fichiers)} fichiers")
            # Sauvegarder fichiers sur disque (OVHcloud)
            if _persist:
                analysis_id = str(uuid.uuid4())[:8]
                for f_save in fichiers:
                    await f_save.seek(0)
                    raw_save = await f_save.read()
                    save_uploaded_file(f_save.filename, raw_save, analysis_id)

        # Persister l'etat apres analyse
        _save_state()

        # Toujours generer le rapport HTML pour l'inclure dans la reponse JSON
        try:
            html_report = orchestrator.report_generator._construire_html(result)
        except Exception:
            html_report = ""

        if format_rapport == "html":
            return HTMLResponse(html_report)

        findings = result.findings
        constats = []
        for f in findings:
            # Parse details_technique JSON for period/rubrique/document
            dt = {}
            if f.details_technique:
                try:
                    dt = json.loads(f.details_technique)
                except (json.JSONDecodeError, TypeError):
                    dt = {}
            constats.append({
                "id": f.id,
                "categorie": f.categorie.value,
                "severite": f.severite.value,
                "titre": f.titre,
                "description": f.description,
                "montant_impact": float(f.montant_impact) if f.montant_impact else 0,
                "score_risque": f.score_risque,
                "recommandation": f.recommandation,
                "reference_legale": f.reference_legale,
                "valeur_attendue": f.valeur_attendue or "",
                "valeur_constatee": f.valeur_constatee or "",
                "documents_concernes": f.documents_concernes or [],
                "periode": dt.get("periode", dt.get("annee", "")),
                "rubrique": dt.get("rubrique", ""),
                "document_source": dt.get("document", ""),
                "detecte_par": f.detecte_par or "",
            })
        recommandations = orchestrator.report_generator._generer_recommandations(findings)

        declarations_out = []
        for decl in result.declarations:
            emp = None
            if decl.employeur:
                emp = {
                    "siren": decl.employeur.siren,
                    "siret": decl.employeur.siret,
                    "raison_sociale": decl.employeur.raison_sociale,
                    "effectif": decl.employeur.effectif,
                    "code_naf": decl.employeur.code_naf,
                }
            salaries = []
            for e in decl.employes:
                cots = [c for c in decl.cotisations if c.employe_id == e.id]
                brut = float(sum(c.base_brute for c in cots)) if cots else float(decl.masse_salariale_brute / max(len(decl.employes), 1))
                net = round(brut * 0.78, 2)
                heures = 151.67
                salaries.append({
                    "nir": e.nir, "nom": e.nom, "prenom": e.prenom,
                    "date_naissance": e.date_naissance.strftime("%d%m%Y") if e.date_naissance else "",
                    "brut_mensuel": round(brut, 2), "net_fiscal": net,
                    "heures": heures,
                    "statut_conventionnel": "01" if e.statut and "cadre" in e.statut.lower() else "02",
                    "num_contrat": f"CTR{e.id[:6]}",
                })
            periode_str = ""
            if decl.periode and decl.periode.debut:
                periode_str = decl.periode.debut.strftime("%Y%m")
            # Determine document nature from parser type_declaration and metadata
            fmt = (decl.type_declaration or "").lower()
            nb_cots = len(decl.cotisations)
            nb_sal = len(decl.employes)
            decl_meta = getattr(decl, "metadata", {}) or {}
            doc_type = decl_meta.get("type_document", "")

            # Map from parser-detected type
            nature_map = {
                # Paie
                "bulletin_de_paie": "Bulletin de paie",
                "bulletin": "Bulletin de paie",
                "livre_de_paie": "Livre de paie / Recapitulatif cotisations",
                # Factures
                "facture_achat": "Facture d achat",
                "facture_vente": "Facture de vente",
                # Contrats
                "contrat_de_travail": "Contrat de travail",
                "contrat_service": "Contrat de prestation de services",
                # Accords
                "accord_interessement": "Accord d interessement",
                "accord_participation": "Accord de participation",
                "accord_entreprise": "Accord d entreprise",
                "accord_nao": "Accord NAO (Negociation annuelle obligatoire)",
                "accord_gpec": "Accord GPEC",
                "accord_teletravail": "Accord teletravail",
                "accord_egalite": "Accord egalite professionnelle",
                "accord_temps_travail": "Accord temps de travail",
                # Attestations
                "attestation": "Attestation employeur",
                # AG
                "pv_ag": "Proces-verbal d assemblee generale",
                "pv_ago": "PV d assemblee generale ordinaire",
                "pv_age": "PV d assemblee generale extraordinaire",
                # Fiscal
                "liasse_fiscale": "Liasse fiscale (2050-2059)",
                "declaration_tva": "Declaration de TVA (CA3/CA12)",
                "declaration_is": "Declaration IS",
                "das2": "DAS2 (honoraires/commissions)",
                "taxe_salaires": "Taxe sur les salaires",
                "cfe_cvae": "CFE/CVAE",
                "fec": "FEC (ecritures comptables)",
                "releve_frais_generaux": "Releve frais generaux (2067)",
                # Comptable
                "bilan": "Bilan / Comptes annuels",
                "compte_resultat": "Compte de resultat",
                "rapport_cac": "Rapport commissaire aux comptes",
                "rapport_gestion": "Rapport de gestion",
                "budget": "Budget previsionnel",
                # Social / RH
                "dpae": "DPAE",
                "registre_personnel": "Registre du personnel",
                "duerp": "DUERP",
                "reglement_interieur": "Reglement interieur",
                "avenant": "Avenant contrat de travail",
                "bilan_social": "Bilan social",
                "note_frais": "Note de frais",
                "rupture_conventionnelle": "Rupture conventionnelle homologuee",
                "cse": "Document CSE", "pv_cse": "PV reunion CSE",
                "budget_cse": "Budget CSE", "rapport_cse": "Rapport CSE",
                "elections_cse": "Elections CSE",
                "france_travail": "Decision France Travail",
                "attestation_are": "Attestation ARE (France Travail)",
                "radiation": "Radiation France Travail",
                "autorisation_licenciement": "Autorisation licenciement (DREETS)",
                "csp": "Contrat securisation professionnelle",
                "medecine_travail": "Avis medecine du travail",
                "visite_embauche": "Visite medicale d embauche",
                "visite_reprise": "Visite de reprise",
                "vip": "Visite information prevention (VIP)",
                "epargne_salariale": "Contrat epargne salariale",
                "pee": "PEE (Plan epargne entreprise)",
                "perco": "PERCO / PERCOL",
                "per": "PER collectif",
                "licenciement": "Lettre de licenciement",
                "formation": "Formation professionnelle",
                "attestation_formation": "Attestation de formation",
                "bilan_competences": "Bilan de competences",
                "vae": "VAE",
                "plan_formation": "Plan de developpement des competences",
                "mutuelle_prevoyance": "Contrat mutuelle / prevoyance",
                "mutuelle": "Contrat mutuelle obligatoire",
                "prevoyance": "Contrat prevoyance",
                "due_mutuelle": "DUE mutuelle obligatoire",
                "dsn": "Declaration sociale nominative (DSN)",
                "dsn_mensuelle": "DSN mensuelle",
                "dsn_evenementielle": "DSN evenementielle",
                "dsn_fin_contrat": "DSN fin de contrat",
                "dsn_arret_travail": "DSN arret de travail",
                "avis_imposition": "Avis d imposition",
                "bordereau_urssaf": "Bordereau URSSAF / Appel cotisations",
                # Juridique
                "statuts": "Statuts de la societe",
                "kbis": "Extrait Kbis / RCS",
                "bail": "Bail commercial",
                "assurance": "Police d assurance",
                "lettre_mission": "Lettre de mission",
                # Commercial
                "devis": "Devis",
                "avoir": "Avoir / Note de credit",
                "bon_commande": "Bon de commande",
                "releve_bancaire": "Releve bancaire",
                "cerfa": "Formulaire CERFA",
                # Image
                "image_non_ocr": "Document image (OCR non disponible)",
            }
            nature = nature_map.get(doc_type, "")

            # Fallback: use type_declaration from parser (also lookup in nature_map)
            if not nature:
                # Try type_declaration directly in nature_map
                nature = nature_map.get(fmt, "")
            if not nature:
                if fmt in ("dsn", "dsn/xml"):
                    nature = "Declaration sociale nominative (DSN)"
                elif fmt == "bulletin":
                    nature = "Bulletin de paie"
                elif fmt == "livre_de_paie":
                    nature = "Livre de paie / Recapitulatif cotisations"
                elif fmt == "facture":
                    nature = "Facture"
                elif fmt == "contrat":
                    nature = "Contrat de travail"
                elif fmt in ("interessement", "participation"):
                    nature = "Accord d " + fmt
                elif fmt == "attestation":
                    nature = "Attestation employeur"
                elif fmt == "accord":
                    nature = "Accord d entreprise"
                elif fmt == "pv_ag":
                    nature = "Proces-verbal d assemblee generale"
                elif fmt == "contrat_service":
                    nature = "Contrat de prestation de services"
                elif fmt == "xml/bordereau":
                    nature = "Bordereau recapitulatif de cotisations (BRC)"
                elif fmt == "image":
                    nature = "Document image"
                elif nb_cots > 0 and nb_sal == 1:
                    nature = "Bulletin de paie"
                elif nb_cots > 0 and nb_sal > 1:
                    nature = "Livre de paie / Recapitulatif cotisations"
                elif nb_sal > 0 and nb_cots == 0:
                    nature = "Liste du personnel / Registre"
                elif float(decl.masse_salariale_brute) > 0:
                    nature = "Bulletin de paie" if nb_sal <= 1 else "Recapitulatif de paie"
                else:
                    nature = "Document comptable / social"
            decl_out = {
                "type": decl.type_declaration,
                "reference": decl.reference,
                "periode": periode_str,
                "employeur": emp,
                "salaries": salaries,
                "masse_salariale_brute": float(decl.masse_salariale_brute),
                "effectif_declare": decl.effectif_declare,
                "nature": nature,
                "nb_cotisations": nb_cots,
                "s89_total_cotisations": decl_meta.get("s89_total_cotisations"),
                "s89_total_brut": decl_meta.get("s89_total_brut"),
                "nb_salaries": nb_sal,
            }
            # Add parsed metadata (net_a_payer, facture amounts, contrat type, etc.)
            if decl_meta.get("net_a_payer"):
                decl_out["net_a_payer"] = decl_meta["net_a_payer"]
            if decl_meta.get("total_patronal"):
                decl_out["total_patronal"] = decl_meta["total_patronal"]
            if decl_meta.get("total_salarial"):
                decl_out["total_salarial"] = decl_meta["total_salarial"]
            if decl_meta.get("date_virement"):
                decl_out["date_virement"] = decl_meta["date_virement"]
            if decl_meta.get("montant_ht"):
                decl_out["montant_ht"] = decl_meta["montant_ht"]
            if decl_meta.get("montant_tva"):
                decl_out["montant_tva"] = decl_meta["montant_tva"]
            if decl_meta.get("montant_ttc"):
                decl_out["montant_ttc"] = decl_meta["montant_ttc"]
            if decl_meta.get("tiers"):
                decl_out["tiers"] = decl_meta["tiers"]
            if decl_meta.get("type_contrat"):
                decl_out["type_contrat"] = decl_meta["type_contrat"]
            if decl_meta.get("remuneration_brute"):
                decl_out["remuneration_brute"] = decl_meta["remuneration_brute"]
            # Accord specifics
            if decl_meta.get("date_accord"):
                decl_out["date_accord"] = decl_meta["date_accord"]
            if decl_meta.get("signataires"):
                decl_out["signataires"] = decl_meta["signataires"]
            if decl_meta.get("convention_collective"):
                decl_out["convention_collective"] = decl_meta["convention_collective"]
            # PV AG specifics
            if decl_meta.get("date_ag"):
                decl_out["date_ag"] = decl_meta["date_ag"]
            if decl_meta.get("nb_resolutions"):
                decl_out["nb_resolutions"] = decl_meta["nb_resolutions"]
            if decl_meta.get("resultat_exercice"):
                decl_out["resultat_exercice"] = decl_meta["resultat_exercice"]
            # Contrat service specifics
            if decl_meta.get("prestataire"):
                decl_out["prestataire"] = decl_meta["prestataire"]
            if decl_meta.get("objet"):
                decl_out["objet"] = decl_meta["objet"]
            # Forward all extra metadata for new document types
            _extra_keys = [
                "exercice_debut", "exercice_fin", "cerfa_numero", "resultat",
                "chiffre_affaires", "total_actif", "total_passif", "benefice",
                "deficit", "tva_collectee", "tva_deductible", "tva_nette",
                "credit_tva", "base_imposable", "montant_impot",
                "nb_beneficiaires", "total_honoraires", "exercice",
                "capitaux_propres", "resultat_net", "resultat_exploitation",
                "ebe", "endettement", "tresorerie", "opinion",
                "date_embauche", "effectif_detecte", "numero_avenant",
                "nouvelle_remuneration", "nb_unites_travail", "nb_risques_identifies",
                "effectif_moyen", "taux_absenteisme", "taux_turnover", "nb_at",
                "denomination", "capital_social", "objet_social", "siege_social",
                "forme_juridique", "rcs", "date_immatriculation",
                "loyer", "duree_bail", "depot_garantie", "prime", "franchise",
                "assureur", "cabinet", "honoraires", "total_frais",
                "solde_initial", "solde_final", "nb_operations",
                "numero_devis", "validite", "numero_avoir", "facture_origine",
                "numero_commande", "annee",
                "ocr_disponible", "avertissements",
            ]
            for ek in _extra_keys:
                val = decl_meta.get(ek)
                if val is not None and val != "" and val != 0 and val != []:
                    decl_out[ek] = val
            declarations_out.append(decl_out)

        # Auto-generer les ecritures comptables a partir des declarations
        # Deduplication: check existing entries by reference to avoid duplicates
        _integration_log = []
        try:
            moteur = get_moteur()
            _existing_refs = {e.libelle for e in moteur.ecritures}
            nb_ecr_paie = 0
            nb_ecr_facture = 0
            for decl in result.declarations:
                d_meta = getattr(decl, "metadata", {}) or {}
                d_type = d_meta.get("type_document", "")
                _integration_log.append(f"Decl: type={decl.type_declaration}, meta_type={d_type}, emps={len(decl.employes)}, cots={len(decl.cotisations)}, masse={float(decl.masse_salariale_brute)}")
                # Ajouter les logs du parser Excel si presents
                parse_log = d_meta.get("parse_log", [])
                for pl in parse_log:
                    _integration_log.append(f"  [PARSER] {pl}")
                # Lister les employes detectes
                for _emp in decl.employes:
                    _integration_log.append(f"  Employe detecte: {_emp.nom} {_emp.prenom} NIR={_emp.nir} id={_emp.id}")

                # --- Ecritures de paie (bulletins, DSN, livres de paie) ---
                if d_type in ("facture_achat", "facture_vente", "devis", "avoir", "bon_commande", "note_frais"):
                    # Documents avec montants: generer ecriture facture
                    ht = Decimal(str(d_meta.get("montant_ht", 0)))
                    tva = Decimal(str(d_meta.get("montant_tva", 0)))
                    ttc = Decimal(str(d_meta.get("montant_ttc", 0)))
                    num_piece = d_meta.get("numero_facture") or d_meta.get("numero_devis") or d_meta.get("numero_avoir") or d_meta.get("numero_commande") or decl.reference
                    dedup_key_fac = f"Facture {num_piece} HT={float(ht):.2f}"
                    if dedup_key_fac in _existing_refs:
                        _integration_log.append(f"  -> Skip doublon facture {num_piece}")
                        continue
                    if ht > 0 or ttc > 0:
                        try:
                            moteur.generer_ecriture_facture(
                                type_doc=d_type,
                                date_piece=date.today(),
                                numero_piece=num_piece,
                                montant_ht=ht,
                                montant_tva=tva if tva > 0 else ht * Decimal("0.20"),
                                montant_ttc=ttc if ttc > 0 else ht * Decimal("1.20"),
                                nom_tiers=d_meta.get("tiers") or d_meta.get("prestataire") or "Tiers",
                            )
                            nb_ecr_facture += 1
                            _existing_refs.add(dedup_key_fac)
                            _integration_log.append(f"  -> Ecriture facture OK: HT={ht} TVA={tva} TTC={ttc}")
                        except Exception as e:
                            _integration_log.append(f"  -> ERREUR facture: {e}")
                    else:
                        _integration_log.append(f"  -> Facture ignoree: HT={ht} TTC={ttc} (montants nuls)")
                    continue

                # Skip types that don't generate accounting entries
                _skip_compta_types = (
                    "contrat_de_travail", "accord_interessement", "accord_participation",
                    "attestation", "contrat_service", "dpae", "registre_personnel",
                    "duerp", "reglement_interieur", "avenant", "bilan_social",
                    "statuts", "kbis", "assurance", "lettre_mission",
                    "bilan", "compte_resultat", "rapport_cac", "rapport_gestion",
                    "budget", "fec", "cerfa", "image_non_ocr", "releve_bancaire",
                )
                _skip_compta_prefixes = ("accord_", "pv_ag", "declaration_", "liasse_")
                if d_type in _skip_compta_types or any(d_type.startswith(p) for p in _skip_compta_prefixes) or d_type in ("das2", "taxe_salaires", "cfe_cvae", "releve_frais_generaux"):
                    _integration_log.append(f"  -> Skip ecriture (type {d_type})")
                    continue  # pas d ecriture comptable de paie

                # Ecritures de paie (with deduplication check)
                if not decl.employes:
                    # Pas d employe mais masse salariale > 0 : generer une ecriture globale
                    if decl.masse_salariale_brute > 0:
                        brut = decl.masse_salariale_brute
                        dedup_key = f"Paie Salaries (global) {float(brut):.2f}"
                        if dedup_key in _existing_refs:
                            _integration_log.append(f"  -> Skip doublon ecriture paie globale (deja existante)")
                        else:
                            d_meta_net = Decimal(str(d_meta.get("net_a_payer", 0)))
                            d_meta_pat = Decimal(str(d_meta.get("total_patronal", 0)))
                            d_meta_sal = Decimal(str(d_meta.get("total_salarial", 0)))
                            cot_sal = float(d_meta_sal) if d_meta_sal > 0 else round(float(brut) * 0.22, 2)
                            cot_pat_total = float(d_meta_pat) if d_meta_pat > 0 else round(float(brut) * 0.45, 2)
                            cot_pat_urssaf = round(cot_pat_total * 0.78, 2)
                            cot_pat_retraite = round(cot_pat_total * 0.22, 2)
                            net_a_payer = float(d_meta_net) if d_meta_net > 0 else round(float(brut) - cot_sal, 2)
                            date_piece = date.today()
                            if decl.periode and decl.periode.debut:
                                date_piece = decl.periode.debut
                            try:
                                moteur.generer_ecriture_paie(
                                    date_piece=date_piece,
                                    nom_salarie="Salaries (global)",
                                    salaire_brut=brut,
                                    cotisations_salariales=Decimal(str(cot_sal)),
                                    cotisations_patronales_urssaf=Decimal(str(cot_pat_urssaf)),
                                    cotisations_patronales_retraite=Decimal(str(cot_pat_retraite)),
                                    net_a_payer=Decimal(str(net_a_payer)),
                                )
                                nb_ecr_paie += 1
                                _existing_refs.add(dedup_key)
                                _integration_log.append(f"  -> Ecriture paie globale OK: brut={brut}")
                            except Exception as e:
                                _integration_log.append(f"  -> ERREUR paie globale: {e}")
                    else:
                        _integration_log.append(f"  -> Pas d employe ni de masse salariale")
                else:
                    for emp in decl.employes:
                        cots = [c for c in decl.cotisations if c.employe_id == emp.id]
                        brut = sum(c.base_brute for c in cots) if cots else Decimal("0")
                        if brut <= 0 and decl.masse_salariale_brute > 0:
                            brut = decl.masse_salariale_brute / max(len(decl.employes), 1)
                        if brut <= 0:
                            _integration_log.append(f"  -> Skip emp {emp.nom}: brut=0")
                            continue
                        nom_sal = f"{emp.prenom} {emp.nom}".strip() or "Salarie"
                        dedup_key = f"Paie {nom_sal} {float(brut):.2f}"
                        if dedup_key in _existing_refs:
                            _integration_log.append(f"  -> Skip doublon ecriture paie {nom_sal}")
                            continue
                        actual_pat = sum(c.montant_patronal for c in cots) if cots else Decimal("0")
                        actual_sal = sum(c.montant_salarial for c in cots) if cots else Decimal("0")
                        net_from_meta = Decimal(str(d_meta.get("net_a_payer", 0)))
                        cot_sal = float(actual_sal) if actual_sal > 0 else round(float(brut) * 0.22, 2)
                        cot_pat_total = float(actual_pat) if actual_pat > 0 else round(float(brut) * 0.45, 2)
                        cot_pat_urssaf = round(cot_pat_total * 0.78, 2)
                        cot_pat_retraite = round(cot_pat_total * 0.22, 2)
                        net_a_payer = float(net_from_meta) if net_from_meta > 0 else round(float(brut) - cot_sal, 2)
                        date_piece = date.today()
                        if decl.periode and decl.periode.debut:
                            date_piece = decl.periode.debut
                        elif decl.periode and decl.periode.fin:
                            date_piece = decl.periode.fin
                        try:
                            moteur.generer_ecriture_paie(
                                date_piece=date_piece,
                                nom_salarie=nom_sal,
                                salaire_brut=brut,
                                cotisations_salariales=Decimal(str(cot_sal)),
                                cotisations_patronales_urssaf=Decimal(str(cot_pat_urssaf)),
                                cotisations_patronales_retraite=Decimal(str(cot_pat_retraite)),
                                net_a_payer=Decimal(str(net_a_payer)),
                            )
                            nb_ecr_paie += 1
                            _existing_refs.add(dedup_key)
                            _integration_log.append(f"  -> Ecriture paie OK: {nom_sal} brut={float(brut):.2f}")
                        except Exception as e:
                            _integration_log.append(f"  -> ERREUR paie {nom_sal}: {e}")
            _integration_log.append(f"COMPTA: {nb_ecr_paie} ecritures paie + {nb_ecr_facture} ecritures facture generees")
        except Exception as e:
            _integration_log.append(f"ERREUR COMPTA GLOBALE: {e}\\n{traceback.format_exc()}")

        # Auto-integrer les salaries dans le module RH + Planning
        # PRINCIPE: On ne cree des contrats QUE pour les employes reellement detectes
        # (avec nom ou NIR). On genere des ALERTES pour les documents manquants.
        nb_rh_new = 0
        nb_rh_updated = 0
        _rh_alertes = []
        # Track document types found for alert generation
        _doc_types_found = set()
        _employees_found = {}  # key: "nom|prenom" or nir -> employee info
        try:
            from datetime import timedelta

            # Phase 1: Collect all employees and document types from all declarations
            for decl in result.declarations:
                d_meta = getattr(decl, "metadata", {}) or {}
                d_type = d_meta.get("type_document", "") or decl.type_declaration or ""
                if d_type:
                    _doc_types_found.add(d_type)

                for emp in decl.employes:
                    if not emp.nom and not emp.nir:
                        continue
                    # Build dedup key
                    if emp.nir:
                        emp_key = emp.nir
                    else:
                        emp_key = f"{(emp.nom or '').strip().lower()}|{(emp.prenom or '').strip().lower()}"
                    if emp_key not in _employees_found:
                        cots = [c for c in decl.cotisations if c.employe_id == emp.id]
                        brut = float(sum(c.base_brute for c in cots)) if cots else 0
                        if brut <= 0 and decl.masse_salariale_brute > 0:
                            brut = float(decl.masse_salariale_brute / max(len(decl.employes), 1))
                        _employees_found[emp_key] = {
                            "nom": emp.nom or "", "prenom": emp.prenom or "",
                            "nir": emp.nir or "", "statut": emp.statut or "",
                            "poste": emp.convention_collective or "",
                            "brut": brut, "date_embauche": emp.date_embauche,
                            "source": d_type or decl.type_declaration,
                        }
                    else:
                        # Update existing with new info if better
                        existing_emp = _employees_found[emp_key]
                        cots = [c for c in decl.cotisations if c.employe_id == emp.id]
                        brut = float(sum(c.base_brute for c in cots)) if cots else 0
                        if brut > existing_emp["brut"]:
                            existing_emp["brut"] = brut
                        if emp.nir and not existing_emp["nir"]:
                            existing_emp["nir"] = emp.nir
                        if emp.convention_collective and not existing_emp["poste"]:
                            existing_emp["poste"] = emp.convention_collective

            _integration_log.append(f"RH: {len(_employees_found)} salaries uniques detectes, {len(_doc_types_found)} types de documents")

            # Phase 2: Create/update RH contracts for found employees only
            for emp_key, emp_info in _employees_found.items():
                nom = emp_info["nom"]
                prenom = emp_info["prenom"]
                nir = emp_info["nir"]
                # Check for existing contract (by NIR or by name)
                existing = [c for c in _rh_contrats if
                            (nir and c.get("nir", "") == nir) or
                            (nom and c.get("nom_salarie", "").strip().lower() == nom.strip().lower() and
                             c.get("prenom_salarie", "").strip().lower() == prenom.strip().lower())]
                if not existing:
                    brut = emp_info["brut"]
                    is_cadre = emp_info["statut"] and "cadre" in emp_info["statut"].lower()
                    date_debut_str = ""
                    if emp_info["date_embauche"]:
                        date_debut_str = emp_info["date_embauche"].strftime("%Y-%m-%d")
                    else:
                        date_debut_str = date.today().strftime("%Y-%m-%d")
                    poste = emp_info["poste"] or ("Cadre" if is_cadre else "Employe")
                    contrat = {
                        "id": str(uuid.uuid4())[:8],
                        "type_contrat": "CDI",
                        "nom_salarie": nom,
                        "prenom_salarie": prenom,
                        "poste": poste,
                        "date_debut": date_debut_str,
                        "date_fin": "",
                        "salaire_brut": str(round(brut, 2)) if brut > 0 else "0",
                        "temps_travail": "temps_complet",
                        "duree_hebdo": "35",
                        "convention_collective": "",
                        "periode_essai_jours": "0",
                        "motif_cdd": "",
                        "statut": "actif",
                        "nir": nir,
                        "verifie": False,
                        "source": "deduit_analyse (" + emp_info["source"] + ")",
                        "date_creation": datetime.now().isoformat(),
                    }
                    _rh_contrats.append(contrat)
                    nb_rh_new += 1
                    _integration_log.append(f"  -> Fiche salarie deduite: {prenom} {nom} brut={brut:.2f} (a verifier)")
                else:
                    # Update existing contract with new info
                    c = existing[0]
                    brut = emp_info["brut"]
                    if brut > 0 and (not c.get("salaire_brut") or c.get("salaire_brut") == "0"):
                        c["salaire_brut"] = str(round(brut, 2))
                        nb_rh_updated += 1
                    if nir and not c.get("nir"):
                        c["nir"] = nir
                        nb_rh_updated += 1

            # Phase 3: Generate alerts for missing mandatory documents
            has_dpae = any(t in _doc_types_found for t in ("dpae",))
            has_contrat = any(t in _doc_types_found for t in ("contrat_de_travail", "contrat"))
            has_registre = any(t in _doc_types_found for t in ("registre_personnel",))
            has_duerp = any(t in _doc_types_found for t in ("duerp",))
            has_reglement = any(t in _doc_types_found for t in ("reglement_interieur",))

            if _employees_found and not has_dpae:
                _rh_alertes.append({
                    "type": "absence_document",
                    "severite": "haute",
                    "titre": "DPAE non importee",
                    "description": f"Aucun accuse de reception DPAE n a ete importe pour {len(_employees_found)} salarie(s) identifie(s). Importez les accuses de reception URSSAF pour verifier la conformite. La DPAE est obligatoire avant toute embauche.",
                    "reference_legale": "Art. L.1221-10 et R.1221-1 Code du travail - Amende 1097 EUR/salarie",
                })
            if _employees_found and not has_contrat:
                _rh_alertes.append({
                    "type": "absence_document",
                    "severite": "haute",
                    "titre": "Contrat de travail absent",
                    "description": f"Aucun contrat de travail n a ete trouve pour {len(_employees_found)} salarie(s). Le contrat ecrit est obligatoire pour tout CDD et recommande pour tout CDI (art. L.1221-1 Code du travail).",
                    "reference_legale": "Art. L.1221-1 et L.1242-12 Code du travail",
                })
            if _employees_found and not has_registre:
                _rh_alertes.append({
                    "type": "absence_document",
                    "severite": "moyenne",
                    "titre": "Registre unique du personnel absent",
                    "description": "Aucun registre unique du personnel n a ete fourni. Ce document est obligatoire dans toute entreprise (art. L.1221-13 Code du travail).",
                    "reference_legale": "Art. L.1221-13 Code du travail",
                })
            if not has_duerp:
                _rh_alertes.append({
                    "type": "absence_document",
                    "severite": "moyenne",
                    "titre": "DUERP absent",
                    "description": "Aucun Document Unique d Evaluation des Risques Professionnels n a ete fourni. Ce document est obligatoire pour tout employeur (art. R.4121-1 Code du travail).",
                    "reference_legale": "Art. R.4121-1 Code du travail",
                })
            # Store alerts in knowledge base
            kb = _biblio_knowledge
            if "alertes_contextuelles" not in kb:
                kb["alertes_contextuelles"] = []
            for alerte in _rh_alertes:
                if not any(a.get("titre") == alerte["titre"] for a in kb["alertes_contextuelles"]):
                    kb["alertes_contextuelles"].append(alerte)

            _integration_log.append(f"RH: {nb_rh_new} fiche(s) deduite(s), {nb_rh_updated} mise(s) a jour, {len(_rh_alertes)} alerte(s)")
        except Exception as e:
            _integration_log.append(f"ERREUR RH GLOBALE: {e}\\n{traceback.format_exc()}")

        # Build file info with per-file parse status and document type
        # Use source_document_id mapping (not index) for reliability
        fichiers_info = []
        for i, f in enumerate(fichiers):
            ext = Path(f.filename).suffix.lower() if f.filename else ""
            finfo = {"nom": f.filename, "extension": ext, "index": i}
            # Find matching declaration by source_document_id
            matched_decl_fi = None
            if i < len(_docs_ordered):
                doc_obj_fi = _docs_ordered[i]
                matching_fi = _doc_to_decls.get(doc_obj_fi.id, [])
                if matching_fi:
                    matched_decl_fi = matching_fi[0]
            if matched_decl_fi is not None:
                decl = matched_decl_fi
                d_meta = getattr(decl, "metadata", {}) or {}
                doc_type = d_meta.get("type_document", "")
                nature_labels = {
                    "bulletin_de_paie": "Bulletin de paie", "bulletin": "Bulletin de paie",
                    "livre_de_paie": "Livre de paie",
                    "facture": "Facture", "facture_achat": "Facture d achat", "facture_vente": "Facture de vente",
                    "contrat_de_travail": "Contrat de travail", "contrat_service": "Contrat de prestation",
                    "accord_interessement": "Accord interessement", "accord_participation": "Accord participation",
                    "attestation": "Attestation employeur",
                    "accord_entreprise": "Accord d entreprise", "accord_nao": "Accord NAO",
                    "accord_gpec": "Accord GPEC", "accord_teletravail": "Accord teletravail",
                    "accord_egalite": "Accord egalite pro", "accord_temps_travail": "Accord temps de travail",
                    "pv_ag": "PV assemblee generale", "pv_ago": "PV AG ordinaire", "pv_age": "PV AG extraordinaire",
                    # Fiscal
                    "liasse_fiscale": "Liasse fiscale", "declaration_tva": "Declaration TVA",
                    "declaration_is": "Declaration IS", "das2": "DAS2",
                    "taxe_salaires": "Taxe salaires", "cfe_cvae": "CFE/CVAE",
                    "fec": "FEC", "releve_frais_generaux": "Frais generaux (2067)",
                    # Comptable
                    "bilan": "Bilan", "compte_resultat": "Compte de resultat",
                    "rapport_cac": "Rapport CAC", "rapport_gestion": "Rapport de gestion", "budget": "Budget",
                    # Social/RH
                    "declaration_dsn": "DSN (Declaration Sociale Nominative)",
                    "dsn": "DSN", "dsn_mensuelle": "DSN mensuelle",
                    "dsn_evenementielle": "DSN evenementielle",
                    "dsn_fin_contrat": "DSN fin de contrat",
                    "dsn_arret_travail": "DSN arret de travail",
                    "dpae": "DPAE", "registre_personnel": "Registre du personnel",
                    "duerp": "DUERP", "reglement_interieur": "Reglement interieur",
                    "avenant": "Avenant", "bilan_social": "Bilan social", "note_frais": "Note de frais",
                    "rupture_conventionnelle": "Rupture conventionnelle",
                    "cse": "Document CSE", "pv_cse": "PV reunion CSE",
                    "budget_cse": "Budget CSE", "rapport_cse": "Rapport CSE",
                    "elections_cse": "Elections CSE",
                    "france_travail": "Decision France Travail",
                    "attestation_are": "Attestation ARE", "radiation": "Radiation France Travail",
                    "inscription": "Inscription France Travail",
                    "autorisation_licenciement": "Autorisation licenciement",
                    "csp": "CSP (Contrat securisation pro)",
                    "medecine_travail": "Medecine du travail",
                    "visite_embauche": "Visite embauche", "visite_reprise": "Visite reprise",
                    "vip": "VIP (Visite info prevention)",
                    "epargne_salariale": "Epargne salariale",
                    "pee": "PEE", "perco": "PERCO/PERCOL", "per": "PER collectif",
                    "licenciement": "Lettre de licenciement",
                    "formation": "Formation professionnelle",
                    "attestation_formation": "Attestation de formation",
                    "bilan_competences": "Bilan de competences",
                    "vae": "VAE (Validation acquis)",
                    "plan_formation": "Plan de formation",
                    "mutuelle_prevoyance": "Mutuelle / Prevoyance",
                    "mutuelle": "Contrat mutuelle", "prevoyance": "Contrat prevoyance",
                    "due_mutuelle": "DUE mutuelle obligatoire",
                    "avis_imposition": "Avis d imposition",
                    "bordereau_urssaf": "Bordereau URSSAF",
                    # Juridique
                    "statuts": "Statuts", "kbis": "Kbis", "bail": "Bail",
                    "assurance": "Assurance", "lettre_mission": "Lettre mission",
                    # Commercial
                    "devis": "Devis", "avoir": "Avoir", "bon_commande": "Bon de commande",
                    "releve_bancaire": "Releve bancaire", "cerfa": "CERFA",
                    "image_non_ocr": "Image (OCR indisponible)",
                    "plaquette": "Plaquette / Brochure",
                    "scan_sans_texte": "PDF scan (sans texte)",
                }
                is_non_exploitable = d_meta_lib.get("exploitable") is False
                if is_non_exploitable:
                    finfo["statut"] = "non_exploitable"
                    finfo["type_document"] = nature_labels.get(doc_type, "Document non exploitable")
                    finfo["message"] = d_meta_lib.get("message", "Ce document ne contient pas de donnees exploitables par le moteur d analyse.")
                elif doc_type == "inconnu" or not doc_type:
                    finfo["statut"] = "non_reconnu"
                    finfo["type_document"] = "Document non reconnu"
                    finfo["message"] = "Le type de ce document n a pas pu etre identifie. Les informations detectees ont ete extraites en mode generique."
                elif doc_type == "image_non_ocr":
                    finfo["statut"] = "analyse"
                    finfo["type_document"] = nature_labels.get(doc_type, "Image")
                    finfo["message"] = "Image classifiee par nom de fichier. L extraction OCR n est pas disponible sur cette plateforme. Renommez vos fichiers de maniere descriptive pour une meilleure classification."
                else:
                    finfo["statut"] = "analyse"
                    finfo["type_document"] = nature_labels.get(doc_type, doc_type.replace("_", " ").title())
                finfo["nb_employes"] = len(decl.employes)
                finfo["nb_cotisations"] = len(decl.cotisations)
                finfo["masse_salariale"] = float(decl.masse_salariale_brute)
            elif ext and ext not in SUPPORTED_EXTENSIONS:
                finfo["statut"] = "format_non_supporte"
                finfo["type_document"] = "Format non supporte"
                finfo["message"] = f"Le format {ext} n est pas supporte. Formats acceptes: PDF, Excel, CSV, DSN, XML, Images, TXT, DOCX."
            else:
                finfo["statut"] = "erreur_analyse"
                finfo["type_document"] = "Erreur d analyse"
                finfo["message"] = "L analyse de ce fichier a echoue."
            fichiers_info.append(finfo)

        # Count unrecognized and non-exploitable files
        nb_non_reconnus = sum(1 for fi in fichiers_info if fi.get("statut") == "non_reconnu")
        nb_non_exploitables = sum(1 for fi in fichiers_info if fi.get("statut") == "non_exploitable")
        nb_erreurs = sum(1 for fi in fichiers_info if fi.get("statut") in ("format_non_supporte", "erreur_analyse"))

        response_data = {
            "synthese": {
                "nb_constats": len(findings),
                "nb_anomalies": result.nb_anomalies,
                "nb_incoherences": result.nb_incoherences,
                "nb_critiques": result.nb_critiques,
                "impact_financier_total": float(result.impact_total),
                "score_risque_global": result.score_risque_global,
                "nb_fichiers": len(result.documents_analyses),
                "nb_fichiers_non_reconnus": nb_non_reconnus,
                "nb_fichiers_non_exploitables": nb_non_exploitables,
                "nb_fichiers_erreur": nb_erreurs,
            },
            "constats": constats,
            "recommandations": recommandations,
            "declarations": declarations_out,
            "fichiers_info": fichiers_info,
            "mode_analyse": mode_analyse,
            "html_report": html_report,
            "knowledge_summary": _get_knowledge_summary(),
            "integration": {
                "compta_ecritures_paie": nb_ecr_paie,
                "compta_ecritures_facture": nb_ecr_facture,
                "rh_fiches_deduites": nb_rh_new,
                "rh_contrats_maj": nb_rh_updated,
                "rh_planning_crees": 0,
                "alertes_rh": _rh_alertes,
                "documents_detectes": sorted(_doc_types_found),
                "salaries_uniques": len(_employees_found),
                "salaries_deduits": [
                    {"id": c["id"], "nom": c["nom_salarie"], "prenom": c["prenom_salarie"],
                     "poste": c["poste"], "brut": c["salaire_brut"], "verifie": c.get("verifie", True)}
                    for c in _rh_contrats if not c.get("verifie", True)
                ],
                "log": _integration_log,
            },
            "limites": {"fichiers_max": 20, "taille_max_mo": 500}}

        response_data["session_id"] = result.session_id

        # --- Scellement dans la chaine de preuve ---
        try:
            doc_list = [{"nom_fichier": fi.get("nom", ""), "sha256": fi.get("sha256", ""),
                         "taille": fi.get("taille", 0)} for fi in fichiers_info]
            proof_record = ScoreProofRecord.create(
                session_id=result.session_id,
                documents=doc_list,
                constats=constats,
                scores={},  # Score triple calcule cote client — sera scelle via /api/proof/seal-score
                version_moteur="4.0",
                version_constantes=hashlib.sha256(
                    (Path(__file__).parent.parent / "urssaf_analyzer" / "config" / "constants.py").read_bytes()
                ).hexdigest()[:16],
                operateur=user_email,
            )
            _proof_chain.append("analyse_complete", {
                "session_id": result.session_id,
                "nb_documents": len(result.documents_analyses),
                "nb_constats": len(findings),
                "score_risque_global": result.score_risque_global,
                "impact_financier_total": float(result.impact_total),
                "documents_hashes": [d["sha256"] for d in doc_list if d["sha256"]],
                "operateur": user_email,
                "proof_record_hash": proof_record["record_hash"],
            })
        except Exception as e:
            logger.warning("Erreur scellement preuve: %s", e)

        return response_data


