@app.get("/api/bibliotheque/knowledge/audit")
async def knowledge_audit(
    annee_debut: int = Query(0),
    annee_fin: int = Query(0),
):
    """Genere un rapport d'audit complet base sur la base de connaissances.
    Supporte le controle pluri-annuel (jusqu'a N-5). Les regles sont adaptees a chaque annee."""
    ks = _get_knowledge_summary()
    kb = _biblio_knowledge

    # --- Controle pluri-annuel : constantes historiques par annee ---
    annee_courante = datetime.now().year
    if annee_fin <= 0:
        annee_fin = annee_courante
    if annee_debut <= 0:
        annee_debut = annee_courante - 5
    annee_debut = max(annee_debut, annee_courante - 5)
    annee_fin = min(annee_fin, annee_courante)
    periode_controle = list(range(annee_debut, annee_fin + 1))

    # Constantes reglementaires historiques (PASS, SMIC, seuils)
    _CONSTANTES_HIST = {
        2021: {"pass": 41136, "smic_h": 10.25, "smic_m": 1554.58, "plafond_ss_m": 3428, "seuil_cse": 11, "seuil_participation": 50, "taux_at_moyen": 2.28, "forfait_social_pee": 20, "taux_agff": 2.0},
        2022: {"pass": 41136, "smic_h": 10.57, "smic_m": 1603.12, "plafond_ss_m": 3428, "seuil_cse": 11, "seuil_participation": 50, "taux_at_moyen": 2.28, "forfait_social_pee": 20, "taux_agff": 2.0},
        2023: {"pass": 43992, "smic_h": 11.52, "smic_m": 1747.20, "plafond_ss_m": 3666, "seuil_cse": 11, "seuil_participation": 50, "taux_at_moyen": 2.24, "forfait_social_pee": 20, "taux_agff": 2.0},
        2024: {"pass": 46368, "smic_h": 11.65, "smic_m": 1766.92, "plafond_ss_m": 3864, "seuil_cse": 11, "seuil_participation": 50, "taux_at_moyen": 2.23, "forfait_social_pee": 20, "taux_agff": 2.0},
        2025: {"pass": 47100, "smic_h": 11.88, "smic_m": 1801.80, "plafond_ss_m": 3925, "seuil_cse": 11, "seuil_participation": 50, "taux_at_moyen": 2.22, "forfait_social_pee": 20, "taux_agff": 2.0},
        # 2026 : valeurs 2025 reconduites (actualiser des publication des textes 2026)
        2026: {"pass": 47100, "smic_h": 11.88, "smic_m": 1801.84, "plafond_ss_m": 3925, "seuil_cse": 11, "seuil_participation": 50, "taux_at_moyen": 2.20, "forfait_social_pee": 20, "taux_agff": 2.0},
    }
    def _cst(annee, cle):
        return _CONSTANTES_HIST.get(annee, _CONSTANTES_HIST.get(2026, {})).get(cle, 0)

    # Regles specifiques par annee (entree en vigueur)
    _REGLES_PAR_ANNEE = {
        "ppv": 2022,  # Prime de partage de la valeur (ex Macron) - Loi 2022-1158
        "bonus_malus_chomage": 2023,  # Modulation taux chomage - Decret 2023-33
        "facturation_electronique_reception": 2024,  # Obligation reception - Ordonnance 2021-1190
        "facturation_electronique_emission": 2026,  # Obligation emission
        "entretien_pro_bilan_6ans": 2020,  # Bilan obligatoire tous les 6 ans - Loi 2018-771
        "referent_harcelement_cse": 2019,  # Loi 2018-771
        "index_egalite_250": 2019,  # Index egalite >= 250 sal
        "index_egalite_50": 2020,  # Index egalite >= 50 sal
        "c2p_6_facteurs": 2018,  # C2P remplace C3P
        "pas_prelevement_source": 2019,  # PAS obligatoire
        "cse_obligatoire": 2020,  # Fin periode transitoire CE/DP -> CSE
        "activite_partielle_longue_duree": 2021,  # APLD - Decret 2020-926
    }

    # --- AUDIT SOCIAL (CSS + CT) ---
    social_checks = []

    # 1. DPAE (L.1221-10 CT) - Controle de presence uniquement
    nb_dpae_docs = len([d for d in _doc_library if d.get("nature") == "dpae"])
    social_checks.append(_audit_check(
        "DPAE (Declaration prealable a l embauche)",
        "Art. L.1221-10 CT",
        nb_dpae_docs > 0 or ks["nb_contrats_rh"] == 0,
        f"{nb_dpae_docs} accuse(s) de reception DPAE importe(s) pour {ks['nb_contrats_rh']} salarie(s)" if nb_dpae_docs > 0 else ("Non applicable (aucun salarie)" if ks["nb_contrats_rh"] == 0 else f"Aucun accuse de reception DPAE importe pour {ks['nb_contrats_rh']} salarie(s) - importez les AR URSSAF"),
        "Accuses de reception DPAE delivres par l URSSAF",
        incidence="Amende 1097 EUR par salarie. Travail dissimule si absence deliberee (delit penal).",
    ))

    # 2. Contrats de travail (L.1221-1 CT)
    social_checks.append(_audit_check(
        "Contrats de travail complets et signes",
        "Art. L.1221-1 CT",
        ks["nb_contrats_rh"] > 0 and ks["nb_contrats_rh"] >= ks["nb_salaries_connus"],
        f"{ks['nb_contrats_rh']} contrat(s) pour {ks['nb_salaries_connus']} salarie(s) detecte(s)" if ks["nb_contrats_rh"] > 0 else "Aucun contrat enregistre",
        "Contrats de travail signes pour chaque salarie",
    ))

    # 3. DSN / Bulletins rapprochement (R.133-14 CSS) - Rapprochement des masses
    # Calculer le rapprochement reel des masses salariales BS vs DSN vs LDP
    masses_bs = {}  # periode -> {"brut": x, "refs": [...]}
    masses_dsn = {}
    masses_ldp = {}
    for bp in kb["bulletins_paie"]:
        per = bp.get("periode", "")
        if per:
            if per not in masses_bs:
                masses_bs[per] = {"brut": 0, "refs": [], "patronal": 0, "salarial": 0}
            masses_bs[per]["brut"] += bp.get("masse_salariale", 0)
            masses_bs[per]["patronal"] += float(bp.get("total_patronal", 0))
            masses_bs[per]["salarial"] += float(bp.get("total_salarial", 0))
            masses_bs[per]["refs"].append(bp.get("reference", ""))
    for d in kb["declarations_dsn"]:
        per = d.get("periode", "")
        if per:
            if per not in masses_dsn:
                masses_dsn[per] = {"brut": 0, "refs": [], "s89_brut": 0, "s89_cot": 0}
            masses_dsn[per]["brut"] += d.get("masse_salariale", 0)
            masses_dsn[per]["s89_brut"] += float(d.get("s89_total_brut", 0))
            masses_dsn[per]["s89_cot"] += float(d.get("s89_total_cotisations", 0))
            masses_dsn[per]["refs"].append(d.get("reference", ""))
    # Livre de paie stored separately in pieces_justificatives
    for bp in kb["bulletins_paie"]:
        ref = bp.get("reference", "")
        if ref in (kb["pieces_justificatives"].get("livre_de_paie") or []):
            per = bp.get("periode", "")
            if per:
                if per not in masses_ldp:
                    masses_ldp[per] = {"brut": 0, "refs": []}
                masses_ldp[per]["brut"] += bp.get("masse_salariale", 0)
                masses_ldp[per]["refs"].append(ref)

    # Comparer les masses par periode
    toutes_periodes = sorted(set(list(masses_bs.keys()) + list(masses_dsn.keys()) + list(masses_ldp.keys())))
    ecarts = []
    seuil_ecart = 0.01  # 1% de tolerance
    for per in toutes_periodes:
        bs = masses_bs.get(per)
        dsn = masses_dsn.get(per)
        ldp = masses_ldp.get(per)
        sources = {}
        if bs:
            sources["BS"] = bs["brut"]
        if dsn:
            sources["DSN"] = dsn["brut"]
        if ldp:
            sources["LDP"] = ldp["brut"]
        if len(sources) >= 2:
            vals = list(sources.values())
            ref_val = max(vals)
            if ref_val > 0:
                for s1, v1 in sources.items():
                    for s2, v2 in sources.items():
                        if s1 < s2:
                            ecart_pct = abs(v1 - v2) / ref_val
                            if ecart_pct > seuil_ecart:
                                ecarts.append({
                                    "periode": per,
                                    "source1": s1, "montant1": round(v1, 2),
                                    "source2": s2, "montant2": round(v2, 2),
                                    "ecart": round(abs(v1 - v2), 2),
                                    "ecart_pct": round(ecart_pct * 100, 2),
                                })

    has_rapprochement = ks["has_dsn"] and ks["has_bulletins"]
    rapprochement_ok = has_rapprochement and len(ecarts) == 0
    if ecarts:
        detail_rappr = f"ECARTS DETECTES sur {len(ecarts)} periode(s): "
        for e in ecarts[:3]:
            detail_rappr += f"[{e['periode']}: {e['source1']}={e['montant1']:.2f} vs {e['source2']}={e['montant2']:.2f}, ecart={e['ecart']:.2f} EUR ({e['ecart_pct']:.1f}%)] "
    elif has_rapprochement:
        nb_per_commun = len([p for p in toutes_periodes if p in masses_bs and p in masses_dsn])
        detail_rappr = f"Masses concordantes: {len(kb['declarations_dsn'])} DSN + {len(kb['bulletins_paie'])} BS sur {nb_per_commun} periode(s) commune(s)"
    else:
        detail_rappr = "DSN et/ou bulletins manquants pour rapprochement des masses"
    social_checks.append(_audit_check(
        "Rapprochement des masses BS / DSN / LDP",
        "Art. R.133-14 CSS - Art. L.242-1 CSS",
        rapprochement_ok,
        detail_rappr,
        "DSN mensuelle + bulletins de paie + livre de paie de la meme periode",
        incidence="Redressement URSSAF en cas d ecart significatif entre masse declaree (DSN) et masse versee (bulletins)" if ecarts else "",
        alerte=len(ecarts) > 0,
    ))

    # 4. Taux URSSAF (L.242-1 CSS) - verification reelle des taux
    nb_taux = len(ks["taux_verifies"])
    taux_non_conformes = []
    from urssaf_analyzer.rules.contribution_rules import ContributionRules as _CR
    from urssaf_analyzer.config.constants import ContributionType as _CT
    effectif_audit = max(ks.get("nb_salaries_connus", 0), max((kb["effectifs"].values()), default=0))
    _rules_audit = _CR(effectif_audit)
    for code_t, info_t in ks["taux_verifies"].items():
        taux_c = info_t.get("taux_constate", 0)
        if taux_c > 0:
            try:
                ct_enum = _CT(code_t)
                conforme, attendu = _rules_audit.verifier_taux(ct_enum, Decimal(str(taux_c)), Decimal(str(info_t.get("base", 0))))
                if not conforme and attendu is not None:
                    taux_non_conformes.append({"code": code_t, "constate": taux_c, "attendu": float(attendu)})
            except (ValueError, KeyError):
                pass
    if taux_non_conformes:
        taux_detail = f"{nb_taux} taux verifies, {len(taux_non_conformes)} NON CONFORME(S): "
        for tnc in taux_non_conformes[:3]:
            taux_detail += f"[{tnc['code']}: {tnc['constate']*100:.2f}% vs attendu {tnc['attendu']*100:.2f}%] "
    elif nb_taux > 0:
        taux_detail = f"{nb_taux} taux de cotisation verifies - tous conformes"
    else:
        taux_detail = "Aucun taux verifie - importer des bulletins de paie avec detail des cotisations"
    social_checks.append(_audit_check(
        "Verification des taux URSSAF 2026",
        "Art. L.242-1 CSS - Baremes URSSAF 2026",
        ks["has_bulletins"] and nb_taux > 0 and len(taux_non_conformes) == 0,
        taux_detail,
        "Bulletins de paie avec detail des cotisations",
        incidence="Redressement URSSAF pour application de taux incorrects" if taux_non_conformes else "",
        alerte=len(taux_non_conformes) > 0,
    ))

    # 4bis. Cotisations obligatoires - completude (controle negatif)
    types_cot_presents = set()
    for cot_kb in kb["cotisations"]:
        code_c = cot_kb.get("code", "")
        if code_c:
            types_cot_presents.add(code_c)
    # Cotisations universelles obligatoires
    universelles = [
        ("maladie", "Maladie"),
        ("vieillesse_plafonnee", "Vieillesse plafonnee"),
        ("vieillesse_deplafonnee", "Vieillesse deplafonnee"),
        ("allocations_familiales", "Allocations familiales"),
        ("accident_travail", "AT/MP"),
        ("csg_deductible", "CSG deductible"),
        ("assurance_chomage", "Assurance chomage"),
        ("retraite_complementaire_t1", "Retraite complementaire T1"),
        ("fnal", "FNAL"),
        ("formation_professionnelle", "Formation professionnelle"),
        ("taxe_apprentissage", "Taxe apprentissage"),
    ]
    # Cotisations par seuil
    par_seuil = [
        (11, "versement_mobilite", "Versement mobilite"),
        (20, "peec", "PEEC (1% logement)"),
    ]
    cots_manquantes = []
    cots_presentes = []
    if ks["has_bulletins"] or len(types_cot_presents) > 0:
        for code_u, label_u in universelles:
            if code_u in types_cot_presents:
                cots_presentes.append(label_u)
            else:
                # Tolerance pour CSG/CRDS souvent regroupees
                if code_u == "csg_deductible" and "csg_non_deductible" in types_cot_presents:
                    cots_presentes.append(label_u)
                    continue
                cots_manquantes.append(label_u)
        for seuil_c, code_c, label_c in par_seuil:
            if effectif_audit >= seuil_c:
                if code_c in types_cot_presents:
                    cots_presentes.append(label_c)
                else:
                    cots_manquantes.append(f"{label_c} (obligatoire >= {seuil_c} sal.)")
    if cots_manquantes:
        completude_detail = f"{len(cots_presentes)} cotisation(s) trouvee(s), {len(cots_manquantes)} MANQUANTE(S): " + ", ".join(cots_manquantes[:5])
    elif len(cots_presentes) > 0:
        completude_detail = f"{len(cots_presentes)} cotisations obligatoires presentes - completude OK"
    else:
        completude_detail = "Aucune cotisation analysee - importer des bulletins de paie"
    social_checks.append(_audit_check(
        "Completude des cotisations obligatoires",
        "Art. L242-1 CSS - Art. L2333-64 CGCT - Art. L313-1 CCH",
        len(cots_presentes) > 0 and len(cots_manquantes) == 0,
        completude_detail,
        "Bulletins de paie complets avec toutes les lignes de cotisations",
        incidence="Redressement URSSAF sur 3 ans + majorations 5% + 0.4%/mois pour cotisations non declarees" if cots_manquantes else "",
        alerte=len(cots_manquantes) > 0,
    ))

    # 5. Coherence masse salariale / effectif (L.242-1 CSS)
    masse_par_sal = ks["total_masse_salariale"] / max(ks["nb_salaries_connus"], 1) if ks["nb_salaries_connus"] > 0 else 0
    masse_coherente = ks["total_masse_salariale"] > 0 and ks["nb_salaries_connus"] > 0
    # Verifier si la masse par salarie est plausible (entre SMIC et 15000 EUR/mois)
    masse_alerte = False
    if masse_par_sal > 0:
        smic_m = 1801.84
        if masse_par_sal < smic_m * 0.5:
            masse_alerte = True
            masse_detail_extra = f" - ATTENTION: moyenne {masse_par_sal:.2f} EUR/sal. est anormalement basse (< 50% SMIC)"
        elif masse_par_sal > 15000:
            masse_detail_extra = f" - moyenne {masse_par_sal:.2f} EUR/sal. (a verifier si coherent)"
        else:
            masse_detail_extra = f" - moyenne {masse_par_sal:.2f} EUR/salarie"
    else:
        masse_detail_extra = ""
    social_checks.append(_audit_check(
        "Coherence masse salariale / effectif declare",
        "Art. L.242-1 CSS",
        masse_coherente and not masse_alerte,
        (f"Masse salariale: {ks['total_masse_salariale']:.2f} EUR pour {ks['nb_salaries_connus']} salarie(s)" + masse_detail_extra) if ks["total_masse_salariale"] > 0 else "Pas assez de donnees",
        "Bulletins de paie, DADS ou DSN annuelle",
        alerte=masse_alerte,
    ))

    # 6. Plafonnement PASS (L.241-3 CSS)
    social_checks.append(_audit_check(
        "Plafonnement PASS (vieillesse plafonnee, FNAL)",
        "Art. L.241-3 CSS - PASS 2026: 48 060 EUR",
        ks["has_bulletins"] and ks["nb_cotisations_analysees"] > 0,
        f"{ks['nb_cotisations_analysees']} lignes de cotisations analysees" if ks["nb_cotisations_analysees"] > 0 else "Aucune cotisation analysee",
        "Bulletins avec lignes vieillesse plafonnee",
    ))

    # 7. Detection apprentis (L.6243-2 CT)
    social_checks.append(_audit_check(
        "Detection apprentis et exonerations specifiques",
        "Art. L.6243-2 CT",
        len(ks["exonerations"]) > 0 or ks["has_bulletins"],
        f"{len(ks['exonerations'])} exoneration(s) detectee(s)" if ks["exonerations"] else "Verifiable si bulletins d apprentis importes",
        "Contrats d apprentissage, bulletins specifiques",
    ))

    # 8. NIR / identite (R.114-7 CSS)
    nirs_valides = sum(1 for s in kb["salaries"].values() if s.get("nir") and not s["nir"].startswith("unknown"))
    social_checks.append(_audit_check(
        "Controle NIR / identite des salaries",
        "Art. R.114-7 CSS",
        nirs_valides > 0 and ks["has_multi_docs"],
        f"{nirs_valides} NIR verifies sur {ks['nb_salaries_connus']} salarie(s)" if nirs_valides > 0 else "NIR non disponibles dans les documents importes",
        "Bulletins + DSN avec NIR concordants",
    ))

    # 9. SMIC et minima (L.3231-2 CT)
    salaires_analyses = [s["dernier_brut"] for s in kb["salaries"].values() if s.get("dernier_brut", 0) > 0]
    smic_mensuel = float(_SMIC_MENSUEL)  # SMIC 2025/2026 approximatif
    sous_smic = [b for b in salaires_analyses if b < smic_mensuel and b > 0]
    # Verification minimum conventionnel (si CCN identifiee)
    ccn_ctx = ctx.get("convention_collective", "")
    min_conv_detail = ""
    sous_minimum_conv = []
    if ccn_ctx:
        try:
            from urssaf_analyzer.config.idcc_database import rechercher_idcc, get_ccn_par_idcc
            ccn_found = get_ccn_par_idcc(ccn_ctx)
            if not ccn_found:
                res_idcc = rechercher_idcc(ccn_ctx)
                if res_idcc:
                    ccn_found = get_ccn_par_idcc(res_idcc[0]["idcc"])
            if ccn_found and ccn_found.get("salaire_minimum_conventionnel"):
                min_conv = float(ccn_found["salaire_minimum_conventionnel"])
                sous_minimum_conv = [b for b in salaires_analyses if 0 < b < min_conv]
                if sous_minimum_conv:
                    min_conv_detail = f" | {len(sous_minimum_conv)} sous le minimum conventionnel ({min_conv:.2f} EUR)"
                else:
                    min_conv_detail = f" | Tous conformes au minimum conventionnel ({min_conv:.2f} EUR)"
        except Exception:
            pass
    smic_detail = ""
    if salaires_analyses:
        if sous_smic:
            smic_detail = f"{len(salaires_analyses)} salaire(s) analyse(s), {len(sous_smic)} sous le SMIC mensuel ({smic_mensuel} EUR)"
        else:
            smic_detail = f"{len(salaires_analyses)} salaire(s) conforme(s) au SMIC ({smic_mensuel} EUR)"
        smic_detail += min_conv_detail
    else:
        smic_detail = "Aucun salaire disponible"
    social_checks.append(_audit_check(
        "Verification SMIC et minima conventionnels",
        "Art. L.3231-2 CT - Art. L.2253-1 CT",
        len(salaires_analyses) > 0,
        smic_detail,
        "Bulletins de paie, grille de la convention collective",
        alerte=len(sous_smic) > 0 or len(sous_minimum_conv) > 0,
    ))

    # 10. Blocs DSN (Cahier technique)
    social_checks.append(_audit_check(
        "Blocs obligatoires DSN (S21.G00.06, S21.G00.40, etc.)",
        "Cahier technique DSN - Norme NEODeS",
        ks["has_dsn"],
        f"{len(kb['declarations_dsn'])} DSN importee(s) et analysee(s)" if ks["has_dsn"] else "Aucune DSN importee",
        "Fichier DSN au format NEODeS",
    ))

    # 11. Prevoyance cadres (ANI 17/11/2017)
    social_checks.append(_audit_check(
        "Prevoyance obligatoire cadres (1.50% TA)",
        "ANI 17/11/2017 - Art. 7 CCN Cadres 1947",
        "prevoyance" in kb["pieces_justificatives"],
        "Contrat de prevoyance importe" if "prevoyance" in kb["pieces_justificatives"] else f"{ks['nb_cadres']} cadre(s) detecte(s) - document de prevoyance non importe",
        "Contrat de prevoyance collective, DUE ou accord collectif",
        incidence="Redressement URSSAF : reintegration dans l assiette de cotisations des contributions patronales",
    ))

    # 12. Mutuelle obligatoire (L.911-7 CSS)
    social_checks.append(_audit_check(
        "Complementaire sante obligatoire (mutuelle ANI)",
        "Art. L.911-7 CSS - ANI 11/01/2013 - Loi 2016",
        "mutuelle" in kb["pieces_justificatives"],
        "Justificatif mutuelle importe" if "mutuelle" in kb["pieces_justificatives"] else "Aucun justificatif de complementaire sante importe",
        "Contrat de complementaire sante, DUE ou accord, attestation mutuelle",
        incidence="Amende + redressement URSSAF sur contributions patronales",
    ))

    # 13. DUERP (R.4121-1 CT)
    social_checks.append(_audit_check(
        "Document unique d evaluation des risques (DUERP)",
        "Art. R.4121-1 a R.4121-4 CT",
        "duerp" in kb["pieces_justificatives"],
        "DUERP importe" if "duerp" in kb["pieces_justificatives"] else "DUERP non importe - obligatoire des le 1er salarie",
        "Document unique d evaluation des risques professionnels",
        incidence="Contravention 5eme classe (1500 EUR). Responsabilite penale en cas AT.",
    ))

    # 14. Registre personnel (L.1221-13 CT)
    social_checks.append(_audit_check(
        "Registre unique du personnel",
        "Art. L.1221-13 CT",
        ks["nb_contrats_rh"] > 0 and ks["nb_contrats_rh"] >= ks["nb_salaries_connus"],
        f"Registre reconstitue via {ks['nb_contrats_rh']} contrat(s) RH" if ks["nb_contrats_rh"] > 0 else "Aucun contrat enregistre - registre non verifiable",
        "Registre avec entrees/sorties de tous les salaries",
        incidence="Contravention 4eme classe (750 EUR par salarie concerne)",
    ))

    # 15. Medecine du travail (R.4624-10 CT)
    social_checks.append(_audit_check(
        "Suivi individuel de sante (medecine du travail)",
        "Art. R.4624-10 CT",
        ks["nb_visites_medicales"] > 0,
        f"{ks['nb_visites_medicales']} visite(s) medicale(s) enregistree(s)" if ks["nb_visites_medicales"] > 0 else "Aucune visite medicale enregistree",
        "Fiches d aptitude, convocations, attestations de suivi",
        incidence="Mise en cause de la responsabilite de l employeur en cas de dommage",
    ))

    # 16. Duree du travail (L.3121-1 CT)
    nb_planning = len(_rh_planning)
    social_checks.append(_audit_check(
        "Duree du travail et repos obligatoires",
        "Art. L.3121-1 CT - Art. L.3131-1 CT (11h repos)",
        nb_planning > 0,
        f"{nb_planning} creneau(x) planning enregistre(s)" if nb_planning > 0 else "Aucun planning enregistre - impossible de verifier les durees",
        "Planning, registre des horaires, accords temps de travail",
    ))

    # 17. Egalite professionnelle (L.1142-8 CT)
    nb_actifs = ks["nb_contrats_actifs"]
    social_checks.append(_audit_check(
        "Index egalite professionnelle (si >= 50 salaries)",
        "Art. L.1142-8 CT",
        nb_actifs < 50 or "index_egalite" in kb["pieces_justificatives"],
        "Non applicable (effectif < 50)" if nb_actifs < 50 else ("Index importe" if "index_egalite" in kb["pieces_justificatives"] else "Index non importe - obligatoire >= 50 salaries"),
        "Index egalite, accord egalite professionnelle",
        incidence="Penalite financiere pouvant atteindre 1% de la masse salariale" if nb_actifs >= 50 else "",
    ))

    # 18. CSE (L.2311-2 CT)
    social_checks.append(_audit_check(
        "Comite social et economique (CSE)",
        "Art. L.2311-2 CT",
        nb_actifs < 11 or "pv_cse" in kb["pieces_justificatives"],
        "Non applicable (effectif < 11)" if nb_actifs < 11 else ("PV CSE importe" if "pv_cse" in kb["pieces_justificatives"] else "CSE obligatoire >= 11 salaries - aucun PV importe"),
        "PV elections CSE, registre des PV de reunions",
        incidence="Delit d entrave (L.2317-1 CT): 1 an emprisonnement + 7500 EUR amende" if nb_actifs >= 11 else "",
    ))

    # 19. Formation professionnelle (L.6321-1 CT)
    social_checks.append(_audit_check(
        "Plan de developpement des competences",
        "Art. L.6321-1 CT",
        ks["nb_entretiens"] > 0,
        f"{ks['nb_entretiens']} entretien(s) professionnel(s) enregistre(s)" if ks["nb_entretiens"] > 0 else "Aucun entretien professionnel enregistre",
        "Plan de formation, bilans, entretiens professionnels",
    ))

    # 20. Conges payes (L.3141-1 CT)
    nb_conges = len(_rh_conges)
    social_checks.append(_audit_check(
        "Suivi des conges payes",
        "Art. L.3141-1 CT - 2.5 jours ouvrables / mois",
        nb_conges > 0 or ks["nb_contrats_rh"] == 0,
        f"{nb_conges} conge(s) enregistre(s)" if nb_conges > 0 else "Aucun conge enregistre" if ks["nb_contrats_rh"] > 0 else "Non applicable (aucun salarie)",
        "Registre des conges, compteurs individuels",
    ))

    # 21. Heures supplementaires (L.3121-33 CT)
    social_checks.append(_audit_check(
        "Heures supplementaires - Contingent annuel (220h)",
        "Art. L.3121-33 CT - Art. D.3121-24 CT",
        nb_planning > 0 or ks["has_bulletins"],
        f"Verifiable via {nb_planning} creneau(x) planning" if nb_planning > 0 else "Verifiable si bulletins avec HS importes" if ks["has_bulletins"] else "Aucune donnee disponible",
        "Registre heures sup, bulletins detailles, accords",
    ))

    # 22. RGDU/Reduction generale (L.241-13 CSS)
    social_checks.append(_audit_check(
        "Reduction generale (RGDU 2026)",
        "Art. L.241-13 CSS - Decret 2025",
        ks["has_bulletins"],
        f"Calculable pour {len(salaires_analyses)} salaire(s) verifies" if salaires_analyses else "Non verifiable sans bulletin",
        "Bulletins de paie detailles, masse salariale annuelle",
        incidence="Redressement URSSAF sur reduction indue ou non optimisee",
    ))

    # 23. AT/MP - Taux individuel (D.242-6-1 CSS)
    social_checks.append(_audit_check(
        "Taux AT/MP (notification annuelle)",
        "Art. D.242-6-1 CSS",
        "notification_at" in kb["pieces_justificatives"] or ks["has_bulletins"],
        "Taux AT/MP verifiable via les bulletins" if ks["has_bulletins"] else "Notification de taux AT non importee",
        "Notification annuelle CARSAT, releve de compte AT",
        incidence="Taux AT incorrect = cotisations erronees sur toute l annee",
    ))

    # 24. CSG/CRDS assiette 98.25% (L.136-2 CSS)
    social_checks.append(_audit_check(
        "CSG/CRDS - Assiette 98.25% du brut",
        "Art. L.136-2 CSS - Abattement 1.75% pour frais professionnels",
        ks["has_bulletins"] and ks["nb_cotisations_analysees"] > 0,
        f"Assiette CSG/CRDS verifiable sur {ks['nb_cotisations_analysees']} ligne(s)" if ks["nb_cotisations_analysees"] > 0 else "Aucune ligne CSG/CRDS analysee",
        "Bulletins de paie avec lignes CSG/CRDS detaillees",
    ))

    # 25. Retraite complementaire AGIRC-ARRCO (L.921-1 CSS)
    social_checks.append(_audit_check(
        "Retraite complementaire AGIRC-ARRCO (T1/T2/CEG/CET)",
        "ANI du 17/11/2017 - Art. L.921-1 CSS",
        "retraite_complementaire_t1" in types_cot_presents or ks["has_bulletins"],
        "Cotisations retraite complementaire detectees" if "retraite_complementaire_t1" in types_cot_presents else "Non verifiable sans bulletin",
        "Bulletins de paie, releve de situation AGIRC-ARRCO",
        incidence="Redressement AGIRC-ARRCO + penalites de retard",
    ))

    # 26. DPAE effectuees (L.1221-10 CT)
    nb_dpae = len([d for d in _doc_library if d.get("nature") == "dpae"])
    social_checks.append(_audit_check(
        "DPAE (Declaration Prealable a l Embauche)",
        "Art. L.1221-10 CT - Art. R.1221-1 CT",
        nb_dpae > 0 or ks["nb_contrats_rh"] == 0,
        f"{nb_dpae} DPAE importee(s) pour {ks['nb_contrats_rh']} contrat(s)" if nb_dpae > 0 else ("Non applicable (aucun salarie)" if ks["nb_contrats_rh"] == 0 else "Aucune DPAE importee - obligatoire avant toute embauche"),
        "Accuse de reception DPAE de l URSSAF",
        incidence="Amende 1097 EUR par salarie (travail dissimule: delit penal)" if nb_dpae == 0 and ks["nb_contrats_rh"] > 0 else "",
    ))

    # 27. Contrats de travail (L.1221-1 CT)
    social_checks.append(_audit_check(
        "Contrats de travail ecrits (CDD, temps partiel)",
        "Art. L.1221-1 CT - Art. L.1242-12 CT (CDD) - Art. L.3123-6 CT (temps partiel)",
        ks["nb_contrats_rh"] > 0,
        f"{ks['nb_contrats_rh']} contrat(s) enregistre(s)" if ks["nb_contrats_rh"] > 0 else "Aucun contrat enregistre",
        "Contrats de travail, avenants",
        incidence="Requalification en CDI (CDD sans ecrit) - rappels de salaire et indemnites",
    ))

    # 28. Affichages obligatoires (R.2262-1 CT)
    social_checks.append(_audit_check(
        "Affichages obligatoires dans les locaux",
        "Art. R.2262-1 CT - Art. R.4227-34 CT",
        False,  # Impossible a verifier par l outil
        "Controle visuel necessaire - non verifiable automatiquement. Affichages requis : horaires, convention collective, inspection du travail, securite, harcelement, egalite H/F",
        "Photos des affichages, attestation de conformite",
    ))

    # 29. Reglement interieur (L.1311-2 CT)
    social_checks.append(_audit_check(
        "Reglement interieur (obligatoire >= 50 salaries)",
        "Art. L.1311-2 CT",
        nb_actifs < 50 or "reglement_interieur" in kb["pieces_justificatives"],
        "Non applicable (effectif < 50)" if nb_actifs < 50 else ("Reglement interieur importe" if "reglement_interieur" in kb["pieces_justificatives"] else "Reglement interieur non importe - obligatoire >= 50 salaries"),
        "Reglement interieur depose a l inspection du travail",
        incidence="Sanctions disciplinaires inopposables aux salaries" if nb_actifs >= 50 else "",
    ))

    # 30. Participation / interessement (L.3322-2 CT)
    social_checks.append(_audit_check(
        "Accord de participation (obligatoire >= 50 salaries)",
        "Art. L.3322-2 CT",
        nb_actifs < 50 or "accord_participation" in kb["pieces_justificatives"],
        "Non applicable (effectif < 50)" if nb_actifs < 50 else ("Accord de participation importe" if "accord_participation" in kb["pieces_justificatives"] else "Accord de participation non importe - obligatoire >= 50 salaries"),
        "Accord de participation, PV de negociation",
        incidence="Perte des exonerations sociales et fiscales sur l epargne salariale" if nb_actifs >= 50 else "",
    ))

    # 31. Prescription travail dissimule - couverture N a N-5 (L.8223-1 CT)
    annee_courante = datetime.now().year
    annees_prescrites = set(range(annee_courante - 5, annee_courante + 1))
    annees_couvertes = set()
    for per in kb["periodes_couvertes"]:
        try:
            an = int(str(per)[:4])
            annees_couvertes.add(an)
        except (ValueError, TypeError):
            pass
    annees_manquantes = sorted(annees_prescrites - annees_couvertes)
    couverture_ok = len(annees_manquantes) == 0
    if annees_couvertes:
        couv_detail = f"Annees couvertes: {', '.join(str(a) for a in sorted(annees_couvertes))}."
        if annees_manquantes:
            couv_detail += f" MANQUANTES dans la periode de prescription: {', '.join(str(a) for a in annees_manquantes)}"
        else:
            couv_detail += f" Couverture complete N-5 a N ({annee_courante-5}-{annee_courante})"
    else:
        couv_detail = f"Aucune periode analysee. Pour un controle complet, importez les documents de {annee_courante-5} a {annee_courante}"
    social_checks.append(_audit_check(
        f"Couverture prescription travail dissimule ({annee_courante-5}-{annee_courante})",
        "Art. L.8223-1 CT - Art. L.244-3 CSS (5 ans)",
        couverture_ok,
        couv_detail,
        f"Documents sociaux de {annee_courante-5} a {annee_courante} (bulletins, DSN, contrats, DPAE)",
        incidence="En cas de travail dissimule, la prescription est de 5 ans (redressement URSSAF, sanctions penales). Tous les documents sur cette periode doivent etre conserves et verifiables.",
    ))

    # 32. Detection travail dissimule - indicateurs (L.8221-1 CT)
    indicateurs_td = []
    # Indicateur 1: salaries sans DPAE importee
    if ks["nb_salaries_connus"] > 0 and nb_dpae == 0:
        indicateurs_td.append(f"{ks['nb_salaries_connus']} salarie(s) sans accuse DPAE importe")
    # Indicateur 2: contrats non verifies
    nb_non_verifies = sum(1 for c in _rh_contrats if not c.get("verifie", True))
    if nb_non_verifies > 0:
        indicateurs_td.append(f"{nb_non_verifies} contrat(s) non verifie(s)")
    # Indicateur 3: ecart masse salariale BS vs DSN
    for e in ecarts:
        if e.get("ecart_pct", 0) > 5:
            indicateurs_td.append(f"Ecart masse salariale > 5% en {e['periode']} ({e['source1']} vs {e['source2']})")
    # Indicateur 4: NIR invalides detectes
    nb_nir_invalides = sum(1 for a in kb["anomalies_detectees"] if "nir" in a.get("titre", "").lower() or "nir" in a.get("description", "").lower())
    if nb_nir_invalides > 0:
        indicateurs_td.append(f"{nb_nir_invalides} anomalie(s) NIR detectee(s)")

    td_ok = len(indicateurs_td) == 0
    td_detail = "Aucun indicateur de travail dissimule detecte" if td_ok else "INDICATEURS DETECTES: " + " ; ".join(indicateurs_td)
    social_checks.append(_audit_check(
        "Detection travail dissimule - Indicateurs",
        "Art. L.8221-1 a L.8221-5 CT",
        td_ok,
        td_detail,
        "DPAE, contrats, DSN, bulletins, NIR",
        incidence="Travail dissimule: 3 ans emprisonnement + 45 000 EUR amende (personne physique), 225 000 EUR (personne morale). Redressement forfaitaire 6 mois de salaire/salarie.",
        alerte=len(indicateurs_td) > 0,
    ))

    # 33. Coherence inter-annuelle des effectifs
    effectifs_par_annee = {}
    for per in kb["periodes_couvertes"]:
        try:
            an = int(str(per)[:4])
            effectifs_par_annee.setdefault(an, 0)
            effectifs_par_annee[an] = max(effectifs_par_annee[an], kb["effectifs"].get(str(per), kb["effectifs"].get(per, 0)))
        except (ValueError, TypeError):
            pass
    variation_anormale = False
    detail_eff = ""
    annees_eff = sorted(effectifs_par_annee.keys())
    if len(annees_eff) >= 2:
        for i in range(1, len(annees_eff)):
            prev = effectifs_par_annee[annees_eff[i-1]]
            curr = effectifs_par_annee[annees_eff[i]]
            if prev > 0 and abs(curr - prev) / prev > 0.5:
                variation_anormale = True
                detail_eff += f"Variation anormale {annees_eff[i-1]}->{annees_eff[i]}: {prev}->{curr} salaries. "
        if not variation_anormale:
            detail_eff = f"Effectifs stables sur {len(annees_eff)} annee(s): " + ", ".join(f"{a}={effectifs_par_annee[a]}" for a in annees_eff)
    else:
        detail_eff = "Insuffisant - au moins 2 annees necessaires pour l analyse inter-annuelle"
    social_checks.append(_audit_check(
        "Coherence inter-annuelle des effectifs",
        "Art. L.130-1 CSS",
        not variation_anormale and len(annees_eff) >= 2,
        detail_eff,
        "DSN mensuelles sur plusieurs annees",
        incidence="Variation brusque d effectif peut indiquer embauche/licenciement non declares" if variation_anormale else "",
        alerte=variation_anormale,
    ))

    # 34. Mutuelle / prevoyance obligatoire (L.911-1 CSS)
    has_mutuelle = any(d.get("nature") in ("mutuelle_prevoyance", "mutuelle", "prevoyance", "due_mutuelle") for d in _doc_library)
    social_checks.append(_audit_check(
        "Complementaire sante obligatoire (mutuelle)",
        "Art. L.911-7 CSS - ANI 2013",
        has_mutuelle or ks["nb_contrats_rh"] == 0,
        "Contrat mutuelle / prevoyance importe" if has_mutuelle else ("Non applicable (aucun salarie)" if ks["nb_contrats_rh"] == 0 else "Aucun justificatif mutuelle obligatoire importe"),
        "Contrat collectif mutuelle, DUE ou accord collectif mutuelle",
        incidence="Mise en demeure URSSAF + perte d exonerations sociales sur la mutuelle" if not has_mutuelle and ks["nb_contrats_rh"] > 0 else "",
    ))

    # 35. Visite medicale / suivi sante (R.4624-10 CT)
    has_visite = any(d.get("nature") in ("medecine_travail", "visite_embauche", "visite_reprise", "vip") for d in _doc_library)
    social_checks.append(_audit_check(
        "Suivi medical des salaries (VIP/Visite medicale)",
        "Art. R.4624-10 a R.4624-28 CT",
        has_visite or ks["nb_contrats_rh"] == 0,
        "Avis de medecine du travail importe(s)" if has_visite else ("Non applicable" if ks["nb_contrats_rh"] == 0 else "Aucun avis de medecine du travail importe"),
        "Avis d aptitude, fiches de visite, attestation SPST",
        incidence="Manquement a l obligation de securite (L.4121-1 CT)" if not has_visite and ks["nb_contrats_rh"] > 0 else "",
    ))

    # 36. Formation professionnelle (L.6311-1 CT)
    has_formation = any(d.get("nature") in ("formation", "attestation_formation", "plan_formation", "bilan_competences", "vae") for d in _doc_library)
    social_checks.append(_audit_check(
        "Formation professionnelle / Plan de developpement",
        "Art. L.6311-1 CT - Art. L.6321-1 CT",
        has_formation,
        "Documents formation importes" if has_formation else "Aucun document de formation importe",
        "Plan de developpement des competences, attestations, bilan competences",
    ))

    # 37. Epargne salariale (L.3332-1 CT)
    has_epargne = any(d.get("nature") in ("epargne_salariale", "pee", "perco", "per", "interessement", "accord_interessement", "accord_participation") for d in _doc_library)
    social_checks.append(_audit_check(
        "Epargne salariale (PEE / PERCO / interessement)",
        "Art. L.3332-1 CT - Art. L.3312-1 CT",
        has_epargne,
        "Contrat(s) epargne salariale importe(s)" if has_epargne else "Aucun contrat epargne salariale importe - verifier l obligation le cas echeant",
        "Accord PEE/PERCO, accord interessement/participation, reglement du plan",
    ))

    # 38. CSE / IRP (L.2311-1 CT)
    has_cse = any(d.get("nature") in ("cse", "pv_cse", "budget_cse", "rapport_cse", "elections_cse") for d in _doc_library)
    nb_actifs_cse = max(ks["nb_salaries_connus"], ks["nb_contrats_actifs"])
    social_checks.append(_audit_check(
        "CSE - Comite social et economique (obligatoire >= 11 salaries)",
        "Art. L.2311-1 a L.2311-2 CT",
        has_cse or nb_actifs_cse < 11,
        "Document(s) CSE importe(s)" if has_cse else ("Non applicable (effectif < 11)" if nb_actifs_cse < 11 else "Aucun document CSE importe - obligatoire >= 11 salaries"),
        "PV elections CSE, PV reunions, budget, rapport activites",
        incidence="Delit d entrave (L.2317-1 CT): 1 an emprisonnement + 7500 EUR amende" if not has_cse and nb_actifs_cse >= 11 else "",
    ))

    # 39. Bordereau URSSAF / suivi cotisations
    has_bordereau = any(d.get("nature") in ("bordereau_urssaf",) for d in _doc_library)
    social_checks.append(_audit_check(
        "Bordereaux URSSAF / Justificatifs paiement cotisations",
        "Art. L.243-3 CSS",
        has_bordereau,
        "Bordereau(x) URSSAF importe(s)" if has_bordereau else "Aucun bordereau URSSAF importe",
        "Bordereaux recapitulatifs, avis d appel, justificatifs de paiement URSSAF",
    ))

    # 40. Entretien professionnel biennal (L.6315-1 CT)
    has_entretien_pro = any(d.get("nature") in ("entretien_professionnel", "entretien_biennal", "compte_rendu_entretien") for d in _doc_library)
    social_checks.append(_audit_check(
        "Entretien professionnel biennal",
        "Art. L.6315-1 CT - Tous les 2 ans + bilan tous les 6 ans",
        has_entretien_pro or ks["nb_entretiens"] > 0,
        f"{ks['nb_entretiens']} entretien(s) enregistre(s)" if ks["nb_entretiens"] > 0 else ("Documents entretiens importes" if has_entretien_pro else "Aucun entretien professionnel enregistre - obligatoire tous les 2 ans"),
        "Comptes-rendus d entretiens professionnels signes, bilan a 6 ans",
        incidence="Abondement correctif CPF de 3000 EUR par salarie concerne (art. L.6315-1 CT)" if not has_entretien_pro and ks["nb_entretiens"] == 0 and ks["nb_contrats_rh"] > 0 else "",
    ))

    # 41. Referent harcelement (L.1153-5-1 CT)
    has_referent = any(d.get("nature") in ("referent_harcelement", "designation_referent", "charte_harcelement") for d in _doc_library)
    social_checks.append(_audit_check(
        "Referent harcelement sexuel et agissements sexistes",
        "Art. L.1153-5-1 CT (>= 250 salaries) - Art. L.2314-1 CT (CSE)",
        has_referent or nb_actifs < 250,
        "Non applicable (effectif < 250)" if nb_actifs < 250 else ("Document designation referent importe" if has_referent else "Aucune designation de referent harcelement importee - obligatoire >= 250 salaries"),
        "Designation du referent harcelement, charte de prevention",
        incidence="Responsabilite employeur (obligation de prevention, L.4121-1 CT)" if nb_actifs >= 250 and not has_referent else "",
    ))

    # 42. Teletravail - accord ou charte (L.1222-9 CT)
    has_teletravail = any(d.get("nature") in ("accord_teletravail", "charte_teletravail", "avenant_teletravail") for d in _doc_library)
    nb_teletravail_planning = sum(1 for p in _rh_planning if p.get("statut") == "teletravail" or p.get("type_poste") == "teletravail")
    social_checks.append(_audit_check(
        "Teletravail - Accord ou charte",
        "Art. L.1222-9 CT - Art. L.1222-10 CT",
        has_teletravail or nb_teletravail_planning == 0,
        "Accord/charte teletravail importe" if has_teletravail else ("Pas de teletravail detecte" if nb_teletravail_planning == 0 else f"{nb_teletravail_planning} jour(s) teletravail planifie(s) sans accord/charte importe"),
        "Accord collectif teletravail ou charte unilaterale + consultation CSE",
        incidence="Risque de requalification en modification du contrat de travail + accident du travail non couvert" if nb_teletravail_planning > 0 and not has_teletravail else "",
    ))

    # 43. PPV - Prime de partage de la valeur (Loi 2022-1158)
    has_ppv = any(d.get("nature") in ("ppv", "prime_partage_valeur", "accord_ppv") for d in _doc_library)
    social_checks.append(_audit_check(
        "PPV - Prime de partage de la valeur",
        "Loi 2022-1158 du 16/08/2022 - Art. 1 (ex-prime Macron)",
        True,  # Non obligatoire mais recommande
        "Document PPV importe" if has_ppv else "Aucun versement PPV detecte - dispositif facultatif mais avantageux (exoneration sous conditions)",
        "Accord PPV, DUE, bulletins de paie avec prime",
    ))

    # 44. Bonus-malus assurance chomage (L.5422-12 CT)
    social_checks.append(_audit_check(
        "Bonus-malus assurance chomage (si >= 11 salaries, 7 secteurs)",
        "Art. L.5422-12 CT - Decret 2019-797",
        nb_actifs < 11 or ks["has_bulletins"],
        "Non applicable (effectif < 11)" if nb_actifs < 11 else ("Taux chomage verifiable via bulletins importes" if ks["has_bulletins"] else "Non verifiable sans bulletin - taux entre 3% et 5.05% selon taux de separation"),
        "Notification du taux modulé, bulletins avec taux chomage",
        incidence="Sur/sous-cotisation chomage non detectee" if nb_actifs >= 11 and not ks["has_bulletins"] else "",
    ))

    # 45. Versement mobilite (L.2333-64 CGCT)
    has_vm = "versement_mobilite" in types_cot_presents
    social_checks.append(_audit_check(
        "Versement mobilite (transport - si >= 11 salaries)",
        "Art. L.2333-64 CGCT - Variable selon commune AOM",
        nb_actifs < 11 or has_vm or not ks["has_bulletins"],
        "Non applicable (effectif < 11)" if nb_actifs < 11 else ("Cotisation VM detectee sur bulletins" if has_vm else "Versement mobilite non detecte sur bulletins - verifier l assujettissement"),
        "Bulletins de paie avec ligne VM, attestation AOM",
        incidence="Redressement URSSAF + majorations de retard sur 3 ans" if nb_actifs >= 11 and not has_vm and ks["has_bulletins"] else "",
        alerte=nb_actifs >= 11 and not has_vm and ks["has_bulletins"],
    ))

    # 46. Activite partielle / chomage partiel (L.5122-1 CT)
    has_activite_partielle = any(d.get("nature") in ("activite_partielle", "chomage_partiel", "autorisation_ap") for d in _doc_library)
    social_checks.append(_audit_check(
        "Activite partielle (si applicable)",
        "Art. L.5122-1 CT - Art. R.5122-1 CT",
        True,  # Verifiable seulement si applicable
        "Documents activite partielle importes" if has_activite_partielle else "Aucun document d activite partielle importe (non obligatoire si non concerne)",
        "Autorisation DDETS, bulletins avec mention activite partielle, convention FNE",
    ))

    # 47. Accord temps de travail / forfait jours (L.3121-53 CT)
    has_forfait = any(d.get("nature") in ("accord_forfait_jours", "convention_forfait", "accord_temps_travail") for d in _doc_library)
    nb_cadres_kb = ks.get("nb_cadres", 0)
    social_checks.append(_audit_check(
        "Convention de forfait jours (cadres autonomes)",
        "Art. L.3121-53 a L.3121-66 CT",
        has_forfait or nb_cadres_kb == 0,
        "Accord forfait jours importe" if has_forfait else ("Pas de cadre detecte" if nb_cadres_kb == 0 else f"{nb_cadres_kb} cadre(s) detecte(s) - verifier si convention de forfait applicable"),
        "Accord collectif forfait jours, conventions individuelles, suivi charge de travail",
        incidence="Annulation du forfait = rappel d heures supplementaires sur 3 ans" if nb_cadres_kb > 0 and not has_forfait else "",
    ))

    # 48. Penibilite / C2P (L.4163-1 CT)
    has_c2p = any(d.get("nature") in ("c2p", "penibilite", "declaration_penibilite", "fiche_penibilite") for d in _doc_library)
    social_checks.append(_audit_check(
        "Compte professionnel de prevention (C2P)",
        "Art. L.4163-1 CT - Art. D.4163-1 CT",
        has_c2p or ks["nb_contrats_rh"] == 0,
        "Document C2P/penibilite importe" if has_c2p else ("Non applicable (aucun salarie)" if ks["nb_contrats_rh"] == 0 else "Aucune declaration de penibilite importee - obligatoire si facteurs de risque (bruit, temperatures, travail de nuit...)"),
        "Declaration des expositions (DSN bloc S21.G00.34), fiches de penibilite",
        incidence="Cotisation penibilite non versee + sanctions L.4163-16 CT",
    ))

    # 49. GUSO - Guichet Unique du Spectacle Occasionnel (L.7122-22 CT)
    has_guso = any(d.get("nature") in ("guso", "attestation_guso", "declaration_guso", "bordereau_guso") for d in _doc_library)
    nb_intermittents = sum(1 for c in _rh_contrats if c.get("type_contrat") in ("cddu", "intermittent", "cachet") or c.get("convention") in ("spectacle", "audiovisuel"))
    social_checks.append(_audit_check(
        "GUSO - Declarations spectacle occasionnel",
        "Art. L.7122-22 CT - Art. R.7122-29 CT",
        has_guso or nb_intermittents == 0,
        f"{nb_intermittents} contrat(s) intermittent(s)/CDDU detecte(s) - documents GUSO importes" if has_guso else ("Non applicable (aucun intermittent detecte)" if nb_intermittents == 0 else f"ALERTE: {nb_intermittents} contrat(s) intermittent(s) sans attestation GUSO - obligation declarative"),
        "Attestation GUSO, bordereau de cotisations spectacle, conge spectacle (15.5%)",
        incidence="Amende de 7500 EUR pour defaut de declaration GUSO + redressement cotisations conge spectacle + Audiens" if nb_intermittents > 0 and not has_guso else "",
        alerte=nb_intermittents > 0 and not has_guso,
    ))

    # 50. GUSO - Conge spectacle et cotisations specifiques
    has_conge_spectacle = any("conge_spectacle" in str(cot.get("code", "")).lower() or "spectacle" in str(cot.get("libelle", "")).lower() for cot in kb["cotisations"])
    social_checks.append(_audit_check(
        "Conge spectacle (15.5%) et cotisations Audiens",
        "Art. D.7121-28 CT - CCN Spectacle vivant (IDCC 3090)",
        has_conge_spectacle or nb_intermittents == 0,
        "Cotisation conge spectacle detectee" if has_conge_spectacle else ("Non applicable" if nb_intermittents == 0 else "Cotisation conge spectacle non detectee sur les bulletins - taux 15.5% a la charge de l employeur"),
        "Bulletins avec ligne conge spectacle (15.5%), cotisations FCAP/Audiens, prevoyance spectacle",
        incidence="Redressement URSSAF/Audiens + majoration. L employeur doit verser 15.5% du salaire brut pour le conge spectacle" if nb_intermittents > 0 and not has_conge_spectacle else "",
    ))

    # 51. GUSO - Licence entrepreneur de spectacle
    has_licence = any(d.get("nature") in ("licence_spectacle", "licence_entrepreneur", "recepisse_licence") for d in _doc_library)
    social_checks.append(_audit_check(
        "Licence entrepreneur de spectacles vivants",
        "Art. L.7122-1 a L.7122-21 CT - Ordonnance 2019-700",
        has_licence or nb_intermittents == 0,
        "Licence/recepisse importe" if has_licence else ("Non applicable" if nb_intermittents == 0 else "Licence entrepreneur de spectacle non importee - obligatoire pour exercer l activite (sauf derogations < 6 representations/an)"),
        "Licence entrepreneur de spectacles (categories 1, 2, 3), recepisse de declaration",
        incidence="Exercice illegal: 2 ans emprisonnement + 30 000 EUR amende (L.7122-17 CT)" if nb_intermittents > 0 and not has_licence else "",
        alerte=nb_intermittents > 0 and not has_licence,
    ))

    # 52. AGESSA / Maison des artistes - artistes-auteurs (R.382-1 CSS)
    has_agessa = any(d.get("nature") in ("agessa", "maison_artistes", "mda", "precompte_agessa", "attestation_agessa") for d in _doc_library)
    nb_artistes_auteurs = sum(1 for c in _rh_contrats if c.get("statut") in ("artiste_auteur", "auteur", "artiste") or c.get("regime") in ("agessa", "mda"))
    social_checks.append(_audit_check(
        "AGESSA / MDA - Precompte artistes-auteurs",
        "Art. R.382-1 a R.382-17 CSS - Art. L.382-1 CSS",
        has_agessa or nb_artistes_auteurs == 0,
        f"Documents AGESSA/MDA importes pour {nb_artistes_auteurs} artiste(s)-auteur(s)" if has_agessa else ("Non applicable (aucun artiste-auteur detecte)" if nb_artistes_auteurs == 0 else f"{nb_artistes_auteurs} artiste(s)-auteur(s) sans justificatif AGESSA/MDA - obligation de precompte des cotisations"),
        "Attestation AGESSA/MDA, bordereaux de precompte (CSG/CRDS + vieillesse 6.90%), certification Diffuseur",
        incidence="Redressement URSSAF du precompte non effectue + penalites. Le diffuseur est redevable du precompte (R.382-17 CSS)" if nb_artistes_auteurs > 0 and not has_agessa else "",
        alerte=nb_artistes_auteurs > 0 and not has_agessa,
    ))

    # 53. Regimes speciaux - Marins (ENIM), Mines, RATP, SNCF, etc.
    has_regime_special = any(d.get("nature") in ("regime_special", "enim", "cnieg", "crpcen", "cavimac", "regime_marin") for d in _doc_library)
    nb_regime_special = sum(1 for c in _rh_contrats if c.get("regime") in ("enim", "cnieg", "crpcen", "cavimac", "mines", "ratp", "sncf", "banque_france", "opera", "comedie_francaise"))
    social_checks.append(_audit_check(
        "Regimes speciaux de securite sociale",
        "Art. L.711-1 CSS - Decrets specifiques par regime",
        has_regime_special or nb_regime_special == 0,
        f"Documents regime special importes ({nb_regime_special} salarie(s) concerne(s))" if has_regime_special else ("Non applicable (aucun salarie en regime special)" if nb_regime_special == 0 else f"{nb_regime_special} salarie(s) en regime special sans justificatif d affiliation"),
        "Attestation d affiliation au regime special, bordereaux de cotisations specifiques",
        incidence="Cotisations versees au mauvais regime = redressement + rappel de cotisations" if nb_regime_special > 0 and not has_regime_special else "",
    ))

    # 54. Controle pluri-annuel : couverture documentaire par annee
    annees_prescrites_ctrl = set(periode_controle)
    annees_docs = set()
    for per in kb["periodes_couvertes"]:
        try:
            annees_docs.add(int(str(per)[:4]))
        except (ValueError, TypeError):
            pass
    annees_docs_ctrl = annees_docs & annees_prescrites_ctrl
    annees_manquantes_ctrl = sorted(annees_prescrites_ctrl - annees_docs)
    couverture_ctrl = len(annees_manquantes_ctrl) == 0
    detail_ctrl = f"Periode de controle: {annee_debut}-{annee_fin}. "
    if annees_docs_ctrl:
        detail_ctrl += f"Annees documentees: {', '.join(str(a) for a in sorted(annees_docs_ctrl))}. "
    if annees_manquantes_ctrl:
        detail_ctrl += f"ANNEES MANQUANTES: {', '.join(str(a) for a in annees_manquantes_ctrl)}"
    else:
        detail_ctrl += "Couverture complete sur la periode."
    social_checks.append(_audit_check(
        f"Controle pluri-annuel ({annee_debut}-{annee_fin}) - Couverture documentaire",
        "Art. L.244-3 CSS (prescription 3 ans URSSAF) - Art. L.8223-1 CT (5 ans travail dissimule)",
        couverture_ctrl,
        detail_ctrl,
        f"Bulletins, DSN, contrats, DPAE pour chaque annee de {annee_debut} a {annee_fin}",
        incidence="Documents manquants = impossibilite de justifier la conformite sur la periode prescrite" if not couverture_ctrl else "",
        alerte=not couverture_ctrl,
    ))

    # 55. Controle pluri-annuel : evolution SMIC et plafonds par annee
    anomalies_smic = []
    for an in periode_controle:
        smic_ref = _cst(an, "smic_m")
        pass_ref = _cst(an, "pass")
        if smic_ref > 0:
            # Verifier si des salaires inferieurs au SMIC pour cette annee
            for bp in kb["bulletins_paie"]:
                bp_an = 0
                try:
                    bp_an = int(str(bp.get("periode", ""))[:4])
                except (ValueError, TypeError):
                    pass
                if bp_an == an:
                    brut_m = bp.get("masse_salariale", 0)
                    if 0 < brut_m < smic_ref * 0.9:  # marge 10% pour temps partiel
                        anomalies_smic.append(f"{an}: brut {brut_m:.0f} EUR < SMIC {smic_ref:.0f} EUR")
    social_checks.append(_audit_check(
        f"Respect du SMIC par annee ({annee_debut}-{annee_fin})",
        "Art. L.3231-2 CT - Art. D.3231-3 CT",
        len(anomalies_smic) == 0,
        "Aucune anomalie SMIC detectee sur la periode" if not anomalies_smic else f"ANOMALIES: {'; '.join(anomalies_smic[:5])}{'...' if len(anomalies_smic) > 5 else ''}",
        "Bulletins de paie avec mention du SMIC applicable par annee",
        incidence="Rappel de salaire + dommages-interets. Contravention 5e classe (1500 EUR/salarie)" if anomalies_smic else "",
        alerte=len(anomalies_smic) > 0,
    ))

    # 56. Controle pluri-annuel : coherence taux cotisations par annee
    taux_anomalies = []
    for an in periode_controle:
        pass_ref = _cst(an, "pass")
        if pass_ref > 0:
            for cot in kb["cotisations"]:
                cot_an = 0
                try:
                    cot_an = int(str(cot.get("periode", ""))[:4])
                except (ValueError, TypeError):
                    pass
                if cot_an == an and cot.get("base_plafonnee", 0) > 0:
                    if cot["base_plafonnee"] > pass_ref * 1.05:
                        taux_anomalies.append(f"{an}: assiette {cot.get('code','?')} {cot['base_plafonnee']:.0f} > PASS {pass_ref}")
    social_checks.append(_audit_check(
        f"Coherence plafonds de cotisations par annee ({annee_debut}-{annee_fin})",
        "Art. L.241-3 CSS - Art. D.242-4 CSS",
        len(taux_anomalies) == 0,
        "Plafonds coherents avec les valeurs PASS de chaque annee" if not taux_anomalies else f"ECARTS: {'; '.join(taux_anomalies[:5])}",
        "Bulletins de paie, DSN, bordereaux URSSAF par annee",
        incidence="Redressement URSSAF si cotisations calculees sur un mauvais plafond" if taux_anomalies else "",
        alerte=len(taux_anomalies) > 0,
    ))

    # --- AUDIT FISCAL (CGI) ---
    fiscal_checks = []

    fiscal_checks.append(_audit_check("Declarations TVA (CA3/CA12)", "Art. 287 CGI",
        "declarations_tva" in kb["pieces_justificatives"],
        "Declarations TVA importees" if "declarations_tva" in kb["pieces_justificatives"] else "Aucune declaration TVA importee",
        "Declarations de TVA, livre des achats/ventes"))

    fiscal_checks.append(_audit_check("Coherence CA declare / comptabilise", "Art. 38 CGI",
        "comptabilite" in kb["pieces_justificatives"] or len(_biblio_knowledge["documents_comptables"]) > 0,
        "Documents comptables disponibles" if "comptabilite" in kb["pieces_justificatives"] else "Aucun document comptable importe",
        "Grand livre, balance, declarations fiscales"))

    fiscal_checks.append(_audit_check("IS/IR - Resultat fiscal", "Art. 209 CGI",
        "liasse_fiscale" in kb["pieces_justificatives"],
        "Liasse fiscale importee" if "liasse_fiscale" in kb["pieces_justificatives"] else "Liasse fiscale non importee",
        "Liasse fiscale (2065/2031), comptes annuels"))

    fiscal_checks.append(_audit_check("CET (CFE + CVAE)", "Art. 1447-0 CGI",
        "cet" in kb["pieces_justificatives"],
        "Documents CET importes" if "cet" in kb["pieces_justificatives"] else "Declarations CFE/CVAE non importees",
        "Declarations 1447-C, 1330-CVAE"))

    fiscal_checks.append(_audit_check("Charges deductibles", "Art. 39 CGI",
        ks["has_bulletins"] or "comptabilite" in kb["pieces_justificatives"],
        "Charges verifiables via les documents importes" if ks["has_bulletins"] else "Aucun justificatif de charges importe",
        "Justificatifs de charges, factures fournisseurs"))

    fiscal_checks.append(_audit_check("Amortissements", "Art. 39B CGI",
        "immobilisations" in kb["pieces_justificatives"],
        "Tableau des immobilisations importe" if "immobilisations" in kb["pieces_justificatives"] else "Tableau des immobilisations non importe",
        "Tableau des immobilisations et amortissements"))

    fiscal_checks.append(_audit_check("Provisions", "Art. 39-1-5 CGI",
        "provisions" in kb["pieces_justificatives"],
        "Releve des provisions importe" if "provisions" in kb["pieces_justificatives"] else "Non verifiable - aucun releve de provisions",
        "Releve des provisions, justificatifs"))

    fiscal_checks.append(_audit_check("TVA intracommunautaire", "Art. 262 ter CGI",
        "deb_des" in kb["pieces_justificatives"],
        "DEB/DES importees" if "deb_des" in kb["pieces_justificatives"] else "Pas de DEB/DES importees",
        "DEB/DES, factures intracommunautaires"))

    fiscal_checks.append(_audit_check("Taxe sur les salaires (si non assujetti TVA)", "Art. 231 CGI",
        ks["has_bulletins"],
        "Verifiable via les bulletins importes" if ks["has_bulletins"] else "Non verifiable sans bulletin",
        "Declaration annuelle taxe sur salaires 2502"))

    # Fiscal 10. DAS-2 - Declaration des honoraires (art. 241 CGI)
    fiscal_checks.append(_audit_check(
        "DAS-2 - Declaration des honoraires (> 2400 EUR/beneficiaire)",
        "Art. 241 a 243-bis CGI - Art. L.133-5-3 CSS",
        "das2" in kb["pieces_justificatives"],
        "DAS-2 importee" if "das2" in kb["pieces_justificatives"] else "DAS-2 non importee - obligatoire si honoraires > 2400 EUR/beneficiaire/an",
        "DAS-2, factures de prestataires/honoraires",
        incidence="Amende de 50% des sommes non declarees (art. 1736 CGI) + majoration 50% si retard > 1 mois",
    ))

    # Fiscal 11. FEC - Fichier des ecritures comptables (art. L.47 A-I LPF)
    fiscal_checks.append(_audit_check(
        "FEC - Fichier des ecritures comptables",
        "Art. L.47 A-I LPF - Art. A.47 A-1 LPF",
        "fec" in kb["pieces_justificatives"],
        "FEC importe" if "fec" in kb["pieces_justificatives"] else "FEC non importe - obligation de presentation en cas de controle",
        "FEC (format xml/txt conforme norme LPF)",
        incidence="Amende 5000 EUR pour non-presentation du FEC + evaluation d office possible",
    ))

    # Fiscal 12. Facturation - Mentions obligatoires (art. 289 CGI)
    nb_factures = len([d for d in _doc_library if d.get("nature") in ("facture_vente", "facture_achat")])
    fiscal_checks.append(_audit_check(
        "Facturation - Mentions obligatoires",
        "Art. 289 CGI - Art. 242 nonies A Annexe II CGI",
        nb_factures > 0,
        f"{nb_factures} facture(s) importee(s)" if nb_factures > 0 else "Aucune facture importee",
        "Factures avec mentions obligatoires (n, date, TVA, identite)",
        incidence="Amende 15 EUR par mention manquante (plafond 25% du montant)" if nb_factures > 0 else "",
    ))

    # Fiscal 13. Delais de conservation (L.102 B LPF)
    fiscal_checks.append(_audit_check(
        "Delais de conservation des documents (6 ans fiscal, 10 ans comptable)",
        "Art. L.102 B LPF - Art. L.123-22 Code de commerce",
        len(_doc_library) > 0,
        f"{len(_doc_library)} document(s) archives dans la bibliotheque" if _doc_library else "Aucun document archive",
        "Ensemble des documents fiscaux et comptables",
        incidence="Impossibilite de justifier en cas de controle = taxation d office",
    ))

    # Fiscal 14. Avantages en nature (art. 82 CGI)
    fiscal_checks.append(_audit_check(
        "Avantages en nature - Evaluation et declaration",
        "Art. 82 CGI - Art. L.242-1 CSS",
        ks["has_bulletins"],
        "Verifiable si avantages en nature mentionnes sur les bulletins" if ks["has_bulletins"] else "Non verifiable sans bulletin",
        "Bulletins de paie, etats des avantages en nature",
    ))

    # Fiscal 15. Credit impot formation dirigeant (EXPIRE 31/12/2024)
    fiscal_checks.append(_audit_check(
        "Credit d impot formation du dirigeant (EXPIRE depuis 31/12/2024)",
        "Art. 244 quater M CGI - Dispositif expire le 31/12/2024",
        "formation_dirigeant" in kb["pieces_justificatives"],
        "Attestation formation importee" if "formation_dirigeant" in kb["pieces_justificatives"] else "Non renseigne - verifier l eligibilite (PME < 250 sal.)",
        "Attestation de formation, cerfa 2079-FCE",
    ))

    # Fiscal 16. PAS - Prelevement a la source (art. 204 A CGI)
    has_pas = any("pas" in str(cot.get("code", "")).lower() or "prelevement_source" in str(cot.get("code", "")).lower() for cot in kb["cotisations"])
    fiscal_checks.append(_audit_check(
        "PAS - Prelevement a la source (retenue employeur)",
        "Art. 204 A a 204 N CGI - Decret 2017-866",
        has_pas or ks["has_bulletins"],
        "PAS verifiable via bulletins importes" if ks["has_bulletins"] else "Non verifiable sans bulletin de paie",
        "Bulletins de paie avec ligne PAS, declarations DSN (bloc PAS S21.G00.50)",
        incidence="Penalite de 5% des retenues non effectuees + interet de retard 0.40%/mois (art. 1759-0 A CGI)",
    ))

    # Fiscal 17. Facturation electronique (art. 289 bis CGI - obligation 2024-2026)
    has_facture_elec = any(d.get("nature") in ("facture_electronique", "piste_audit_fiable", "factur_x") for d in _doc_library)
    fiscal_checks.append(_audit_check(
        "Facturation electronique (obligation progressive 2024-2026)",
        "Art. 289 bis CGI - Ordonnance 2021-1190 - Decret 2022-1299",
        has_facture_elec or nb_factures == 0,
        "Documents facturation electronique importes" if has_facture_elec else ("Pas de facture importee" if nb_factures == 0 else "Aucun justificatif de conformite facturation electronique - obligation progressive (reception 2024, emission 2026)"),
        "Attestation PDP (Plateforme de Dematerialisation Partenaire), factures Factur-X",
        incidence="Amende de 15 EUR par facture non conforme (art. 1737 CGI)" if nb_factures > 0 and not has_facture_elec else "",
    ))

    # Fiscal 18. Taxe apprentissage - solde (art. 1599 ter A CGI)
    has_ta = "taxe_apprentissage" in types_cot_presents
    fiscal_checks.append(_audit_check(
        "Taxe d apprentissage - versement et solde",
        "Art. 1599 ter A CGI - Art. L.6241-1 CT",
        has_ta or not ks["has_bulletins"],
        "Taxe apprentissage detectee sur bulletins" if has_ta else ("Non verifiable sans bulletin" if not ks["has_bulletins"] else "Taxe apprentissage non detectee sur les bulletins"),
        "Bordereau de versement TA, recu liberatoire, attestation OPCO",
        incidence="Redressement URSSAF + majoration de 100% du montant du (art. L.6252-4 CT)" if ks["has_bulletins"] and not has_ta else "",
    ))

    # Fiscal 19. TVA - Autoliquidation (art. 283-2 CGI)
    has_autoliq = any(d.get("nature") in ("autoliquidation_tva", "facture_autoliquidation") for d in _doc_library)
    fiscal_checks.append(_audit_check(
        "TVA - Autoliquidation (sous-traitance BTP, acquisitions intra-UE)",
        "Art. 283-2 CGI - Art. 283-1 CGI",
        True,  # Non obligatoire systematiquement
        "Documents autoliquidation importes" if has_autoliq else "Aucun document d autoliquidation importe (non obligatoire si non concerne)",
        "Factures avec mention autoliquidation, declarations CA3 avec autoliquidation",
    ))

    # Fiscal 20. CVAE - Declaration si CA > 500 000 EUR (art. 1586 ter CGI)
    fiscal_checks.append(_audit_check(
        "CVAE - Cotisation sur la valeur ajoutee (si CA > 500 000 EUR)",
        "Art. 1586 ter CGI - Art. 1586 quater CGI",
        "cvae" in kb["pieces_justificatives"] or "cet" in kb["pieces_justificatives"],
        "Declaration CVAE/CET importee" if "cvae" in kb["pieces_justificatives"] or "cet" in kb["pieces_justificatives"] else "Declaration CVAE non importee - verifier si CA > 500 000 EUR",
        "Declaration 1330-CVAE, declaration 1329-DEF",
        incidence="Amende 150 EUR pour defaut de declaration + interet de retard",
    ))

    # --- COUR DES COMPTES ---
    cdc_checks = []
    cdc_checks.append(_audit_check("Regularite des comptes", "Normes NEP - ISA",
        "comptes_annuels" in kb["pieces_justificatives"],
        "Comptes annuels importes" if "comptes_annuels" in kb["pieces_justificatives"] else "Comptes annuels non importes",
        "Comptes annuels certifies par CAC"))

    cdc_checks.append(_audit_check("Sincerite des ecritures", "Art. L.123-14 Code de commerce",
        len(_biblio_knowledge["documents_comptables"]) > 0 or ks["has_bulletins"],
        "Ecritures verifiables" if len(_biblio_knowledge["documents_comptables"]) > 0 else "Pas de pieces comptables detaillees",
        "Grand livre, pieces justificatives"))

    cdc_checks.append(_audit_check("Image fidele du patrimoine", "Art. L.123-14 Code de commerce",
        "bilan" in kb["pieces_justificatives"],
        "Bilan importe" if "bilan" in kb["pieces_justificatives"] else "Bilan non importe",
        "Bilan, annexe, rapport de gestion"))

    cdc_checks.append(_audit_check("Continuite d exploitation", "NEP 570",
        "previsionnel" in kb["pieces_justificatives"],
        "Previsionnel importe" if "previsionnel" in kb["pieces_justificatives"] else "Previsionnel non disponible",
        "Previsionnels, plan de tresorerie"))

    # CDC 5. Separation des exercices
    cdc_checks.append(_audit_check(
        "Separation des exercices (cut-off)",
        "Art. L.123-12 Code de commerce - PCG art. 313-1",
        "comptabilite" in kb["pieces_justificatives"],
        "Verifiable si ecritures comptables disponibles" if "comptabilite" in kb["pieces_justificatives"] else "Non verifiable sans ecritures comptables",
        "Journal de ventes/achats, ecritures de fin d exercice"))

    # CDC 6. Exhaustivite des charges sociales
    cdc_checks.append(_audit_check(
        "Exhaustivite des charges sociales declarees",
        "Norme ISA 315 (identification des risques) / ISA 500 (elements probants)",
        ks["has_bulletins"] and ks["nb_cotisations_analysees"] > 0,
        f"{ks['nb_cotisations_analysees']} ligne(s) de cotisations verifiee(s)" if ks["nb_cotisations_analysees"] > 0 else "Non verifiable",
        "Bulletins de paie, journal de paie, DSN"))

    # CDC 7. Respect des procedures de marches publics (si applicable)
    cdc_checks.append(_audit_check(
        "Procedures de marches / conventions reglementees",
        "Art. L.225-38 Code de commerce",
        "conventions_reglementees" in kb["pieces_justificatives"],
        "Rapport special CAC importe" if "conventions_reglementees" in kb["pieces_justificatives"] else "Non renseigne - verifier si conventions reglementees existent",
        "Rapport special CAC sur conventions reglementees"))

    # CDC 8. Controle interne
    cdc_checks.append(_audit_check(
        "Procedures de controle interne",
        "NEP 315 - ISA 315",
        "procedures_ci" in kb["pieces_justificatives"],
        "Documentation controle interne importee" if "procedures_ci" in kb["pieces_justificatives"] else "Non renseigne",
        "Documentation des procedures, organigramme, delegations"))

    # CDC 9. Rapprochement bancaire
    has_rappr_banc = any(d.get("nature") in ("rapprochement_bancaire", "releve_bancaire", "etat_rapprochement") for d in _doc_library)
    cdc_checks.append(_audit_check(
        "Rapprochement bancaire",
        "ISA 500 - PCG art. 410-5",
        has_rappr_banc,
        "Document(s) de rapprochement bancaire importe(s)" if has_rappr_banc else "Aucun rapprochement bancaire importe - obligatoire pour justifier la tresorerie",
        "Etats de rapprochement bancaire, releves de compte",
        incidence="Reserves du CAC sur les comptes de tresorerie" if not has_rappr_banc else "",
    ))

    # CDC 10. Annexe aux comptes annuels
    has_annexe = any(d.get("nature") in ("annexe_comptes", "annexe_comptable", "notes_annexes") for d in _doc_library)
    cdc_checks.append(_audit_check(
        "Annexe aux comptes annuels",
        "Art. L.123-14 Code de commerce - PCG art. 531-1",
        has_annexe or "comptes_annuels" in kb["pieces_justificatives"],
        "Annexe importee" if has_annexe else ("Incluse dans les comptes annuels" if "comptes_annuels" in kb["pieces_justificatives"] else "Annexe non importee - obligatoire avec le bilan et le compte de resultat"),
        "Annexe aux comptes annuels (regles et methodes, notes explicatives)",
    ))

    # CDC 11. Rapport de gestion
    has_rapport_gestion = any(d.get("nature") in ("rapport_gestion", "rapport_annuel") for d in _doc_library)
    cdc_checks.append(_audit_check(
        "Rapport de gestion",
        "Art. L.232-1 Code de commerce",
        has_rapport_gestion or nb_actifs < 11,
        "Rapport de gestion importe" if has_rapport_gestion else ("Dispense possible (petite entreprise)" if nb_actifs < 11 else "Rapport de gestion non importe"),
        "Rapport de gestion du dirigeant, rapport du CA",
    ))

    # CDC 12. Depot des comptes annuels (greffe)
    has_depot = any(d.get("nature") in ("depot_comptes", "recepisse_greffe", "kbis") for d in _doc_library)
    cdc_checks.append(_audit_check(
        "Depot des comptes annuels au greffe",
        "Art. L.232-21 a L.232-23 Code de commerce",
        has_depot,
        "Recepisse de depot importe" if has_depot else "Aucun justificatif de depot au greffe importe",
        "Recepisse de depot au greffe, Kbis a jour",
        incidence="Amende de 1500 EUR + astreinte pour non-depot (art. L.123-5-1 C.com)",
    ))

    # CDC 13. Inventaire physique (L.123-12 C.com)
    has_inventaire = any(d.get("nature") in ("inventaire", "inventaire_physique", "etat_stocks") for d in _doc_library)
    cdc_checks.append(_audit_check(
        "Inventaire physique annuel",
        "Art. L.123-12 Code de commerce - PCG art. 410-8",
        has_inventaire,
        "Inventaire importe" if has_inventaire else "Aucun inventaire physique importe - obligatoire au moins une fois par exercice",
        "Proces-verbal d inventaire, etat des stocks valorises",
    ))

    # Rapprochement detaille des masses (donnees supplementaires pour affichage)
    rapprochement_detail = {
        "periodes": toutes_periodes,
        "masses_bs": {p: {"brut": v["brut"], "patronal": v["patronal"], "salarial": v["salarial"]} for p, v in masses_bs.items()},
        "masses_dsn": {p: {"brut": v["brut"], "s89_brut": v["s89_brut"], "s89_cot": v["s89_cot"]} for p, v in masses_dsn.items()},
        "masses_ldp": {p: {"brut": v["brut"]} for p, v in masses_ldp.items()},
        "ecarts": ecarts,
        "seuil_tolerance_pct": seuil_ecart * 100,
    }

    return {
        "social": social_checks,
        "fiscal": fiscal_checks,
        "cour_des_comptes": cdc_checks,
        "knowledge_summary": ks,
        "score_audit": _calculer_score_audit(social_checks, fiscal_checks, cdc_checks),
        "rapprochement_masses": rapprochement_detail,
        "controle_pluriannuel": {
            "annee_debut": annee_debut,
            "annee_fin": annee_fin,
            "periode": periode_controle,
            "constantes_par_annee": {an: _CONSTANTES_HIST.get(an, {}) for an in periode_controle},
            "annees_documentees": sorted(annees_docs_ctrl),
            "annees_manquantes": annees_manquantes_ctrl,
            "couverture_complete": couverture_ctrl,
        },
    }


def _audit_check(nom: str, ref: str, present: bool, detail: str, docs: str, incidence: str = "", alerte: bool = False) -> dict:
    return {
        "nom": nom,
        "reference": ref,
        "present": present,
        "detail": detail,
        "documents_requis": docs,
        "incidence_legale": incidence,
        "alerte": alerte,
    }


def _calculer_score_audit(social, fiscal, cdc) -> dict:
    total = len(social) + len(fiscal) + len(cdc)
    verifies = sum(1 for c in social + fiscal + cdc if c["present"])
    pct = round(verifies / total * 100) if total > 0 else 0
    return {
        "total_checks": total,
        "verifies": verifies,
        "non_verifies": total - verifies,
        "pourcentage": pct,
        "social_verifies": sum(1 for c in social if c["present"]),
        "social_total": len(social),
        "fiscal_verifies": sum(1 for c in fiscal if c["present"]),
        "fiscal_total": len(fiscal),
        "cdc_verifies": sum(1 for c in cdc if c["present"]),
        "cdc_total": len(cdc),
    }


@app.post("/api/documents/bibliotheque/{doc_id}/corriger")
async def corriger_document(
    doc_id: str,
    champ: str = Form(...),
    ancienne_valeur: str = Form(""),
    nouvelle_valeur: str = Form(...),
    corrige_par: str = Form("utilisateur"),
):
    for doc in _doc_library:
        if doc["id"] == doc_id:
            doc["erreurs_corrigees"].append({
                "champ": champ,
                "ancienne_valeur": ancienne_valeur,
                "nouvelle_valeur": nouvelle_valeur,
                "date": datetime.now().isoformat(),
                "par": corrige_par,
            })
            doc["actions"].append({
                "action": f"correction:{champ}",
                "par": corrige_par,
                "date": datetime.now().isoformat(),
            })
            log_action(corrige_par, "correction_document", f"{doc['nom']} {champ}")
            return {"status": "ok"}
    raise HTTPException(404, "Document non trouve")


