@app.post("/api/collaboration/finaliser")
async def finaliser_invitation(
    token: str = Form(...),
    mot_de_passe: str = Form(...),
    confirm: str = Form(""),
):
    for inv in _invitations:
        if inv["token"] == token:
            if inv["statut"] == "active":
                return HTMLResponse("<h2>Ce lien a deja ete utilise.</h2>", 400)
            try:
                user = create_user(
                    inv["email"], mot_de_passe,
                    nom=inv.get("email", "").split("@")[0],
                    prenom="",
                    role=inv["role"],
                    tenant_id=inv.get("tenant_id", ""),
                )
            except ValueError as e:
                return HTMLResponse(f"<h2>Erreur : {e}</h2>", 400)
            inv["statut"] = "active"
            log_action(inv["email"], "activation_compte", f"role={inv['role']}")
            jwt_token = generate_token(user)
            response = HTMLResponse(f"""<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>NormaCheck - Compte active</title></head><body style="font-family:-apple-system,sans-serif;display:flex;justify-content:center;align-items:center;min-height:100vh;background:#f8fafc">
<div style="text-align:center"><h2 style="color:#16a34a">Compte active !</h2><p>Vous pouvez maintenant <a href="/app">acceder a NormaCheck</a>.</p></div></body></html>""")
            set_auth_cookie(response, jwt_token)
            return response
    raise HTTPException(404, "Token invalide")


@app.get("/api/collaboration/equipe")
async def equipe(request: Request):
    user = get_current_user(request)
    tenant_id = user.get("tenant_id", "")
    user_email = user.get("email", "")
    user_role = user.get("role", "collaborateur")
    if user_role == "admin" and tenant_id == "default":
        # Super-admin (tenant "default") voit tout
        inv_filtered = _invitations
        log_filtered = _audit_log[-50:]
    elif user_role in ("admin", "decisionnaire") and tenant_id:
        # Admin/decisionnaire d'un tenant : voit les activites du tenant
        # Inclut les entrees des membres de l'equipe (par email) pour les
        # anciennes entrees sans tenant_id
        team_emails = {u["email"] for u in list_users_by_tenant(tenant_id)}
        inv_filtered = [i for i in _invitations if i.get("tenant_id") == tenant_id]
        log_filtered = [
            e for e in _audit_log
            if e.get("tenant_id") == tenant_id
            or (not e.get("tenant_id") and e.get("profil") in team_emails)
        ][-50:]
    else:
        # Utilisateur standard : voit uniquement ses propres activites
        inv_filtered = [i for i in _invitations if i.get("tenant_id") == tenant_id]
        log_filtered = [e for e in _audit_log if e.get("profil") == user_email][-50:]
    return {
        "invitations": inv_filtered,
        "audit_log": log_filtered,
    }


